INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:169','tvmaze','tvmaze:show:169','watching',20,'Breaking Bad','Breaking Bad follows protagonist Walter White, a chemistry teacher who lives in New Mexico with his wife and teenage son who has cerebral palsy. White is diagnosed with Stage III cancer and given a prognosis of two years left to live. With a new sense of fearlessness based on his medical prognosis, and a desire to secure his family''s financial security, White chooses to enter a dangerous world of drugs and crime and ascends to power in this world. The series explores how a fatal diagnosis such as White''s releases a typical man from the daily concerns and constraints of normal society and follows his transformation from mild family man to a kingpin of the drug trade.','https://static.tvmaze.com/uploads/images/medium_portrait/501/1253519.jpg','2008-01-20',NULL,'2026-07-04T12:48:36.448Z','2026-07-04 12:44:57','2026-07-04 12:52:56',3,13,'2026-07-04T12:48:36.448Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:765','tvmaze','tvmaze:show:765','plan-to-watch',0,'Teen Titans','Five teen superheroes led by Robin the Boy Wonder team up to protect Earth from a new generation of villains. His partners are Starfire, an alien who can fly; Cyborg, a half-human, half-robot with great strength; Raven, an introvert with telekinetic powers; and Beast Boy, who can change into any ki.','https://static.tvmaze.com/uploads/images/medium_portrait/6/15290.jpg','2003-07-19',NULL,'2026-07-04T12:48:12.373Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,0,'2026-07-04T12:48:12.373Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:526','tvmaze','tvmaze:show:526','watching',1,'The Office','Steve Carell stars in The Office, a fresh and funny mockumentary-style glimpse into the daily interactions of the eccentric workers at the Dunder Mifflin paper supply company. Based on the smash-hit British series of the same name and adapted for American Television by Greg Daniels, this fast-paced comedy parodies contemporary American water-cooler culture. Earnest but clueless regional manager Michael Scott believes himself to be an exceptional boss and mentor, but actually receives more eye-rolls than respect from his oddball staff.','https://static.tvmaze.com/uploads/images/medium_portrait/481/1204342.jpg','2005-03-24',NULL,'2026-07-04T12:48:13.697Z','2026-07-04 12:52:56','2026-07-04 12:52:56',9,23,'2026-07-04T12:48:13.697Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:123','tvmaze','tvmaze:show:123','watching',2,'Lost','Out of the blackness, the first thing Jack senses is pain. Then burning sun. A Bamboo forest. Smoke. Screams. With a rush comes the horrible awareness that the plane he was on tore apart in mid-air and crashed on a Pacific island. From there it''s a blur, as his doctor''s instinct kicks in: people need his help.Stripped of everything, the 48 survivors scavenge what they can from the plane for their survival. Some panic. Some pin their hopes on rescue. A few find inner strength they never knew they had -- like Kate, who, with no medical training, suddenly finds herself suturing the doctor''s wounds. Hurley - a man with a warm sense of humor despite the desperate situation - does his best to keep his cool as he helps those around him to survive. Charlie is a faded rock star who harbors a painful secret. Sayid is a Middle Eastern man who must wrestle with the racial profiling directed at him by some of his fellow survivors. Jin and Sun are a Korean couple whose traditions, values and language are foreign, and thus causes much to get lost in the translation. Sawyer has an air of danger surrounding him, and his intense sense of mistrust for everyone around him could prove to be fatal to his fellow castaways. Michael has just gained custody of his nine-year-old son, Walt, after the death of his ex-wife - they are a father and son who don''t even know each other. Locke is a mysterious man who keeps to himself, and who harbors a deeper connection to the island than any of the others. Self-centered Shannon - who actually gives herself a pedicure amid the chaos - and her estranged controlling brother, Boone , constantly bicker and must learn to get along if they are to survive. And young Claire is eight months pregnant and ill-prepared for the hardships of motherhood - especially on a deserted island.','https://static.tvmaze.com/uploads/images/medium_portrait/0/1389.jpg','2004-09-22',NULL,'2026-07-04T12:48:14.724Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,19,'2026-07-04T12:48:14.724Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:465','tvmaze','tvmaze:show:465','completed',3,'Band of Brothers','Drawn from interviews with survivors of Easy Company, as well as their journals and letters, Band of Brothers chronicles the experiences of these men from paratrooper training in Georgia through the end of the war. As an elite rifle company parachuting into Normandy early on D-Day morning, participants in the Battle of the Bulge, and witness to the horrors of war, the men of Easy knew extraordinary bravery and extraordinary fear - and became the stuff of legend. Based on Stephen E. Ambrose''s acclaimed book of the same name.','https://static.tvmaze.com/uploads/images/medium_portrait/80/201679.jpg','2001-09-09',NULL,'2026-07-04T12:48:15.709Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,10,'2026-07-04T12:48:15.709Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:541','tvmaze','tvmaze:show:541','watching',4,'Prison Break','Lincoln Burrows is currently on death row and scheduled to die in a few months for an assassination his younger brother Michael is convinced he did not commit. With no other options and time winding down, Michael takes drastic measures to get himself incarcerated alongside his brother in Fox River State Penitentiary. Once he''s inside, Michael - a structural engineer with the blueprints for the prison - begins to execute an elaborate plan to break Lincoln out and prove him innocent. When Michael arrives at Fox River State Penitentiary, he meets the prison denizens who will, unknowingly, help in his escape plans - his cellmate, the lovelorn Sucre; beautiful prison doctor Dr. Sara Tancredi, who happens to be the governor''s daughter; former mob boss John Abruzzi; and Warden Henry Pope. Meanwhile, outside the prison walls, the brothers'' childhood friend and Lincoln''s lost love, attorney Veronica Donovan, works within the law to free them; Lincoln''s teenage son LJ may be going down a path similar to his convicted father''s; and Secret Service Agent Paul Kellerman''s investigation into Lincoln''s case proves that there may be a national conspiracy.','https://static.tvmaze.com/uploads/images/medium_portrait/104/261034.jpg','2005-08-29',NULL,'2026-07-04T12:48:17.053Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,0,'2026-07-04T12:48:17.053Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:171','tvmaze','tvmaze:show:171','completed',5,'How I Met Your Mother','How I Met Your Mother is a comedy about Ted and how he fell in love. It all starts when Ted''s best friend, Marshall drops the bombshell that he''s going to propose to his long-time girlfriend, Lilya kindergarten teacher. At that moment, Ted realizes that he had better get a move on if he too hopes to find true love. Helping him in his quest is Barney a friend with endless, sometimes outrageous opinions, a penchant for suits and a foolproof way to meet women. When Ted meets Robin he''s sure it''s love at first sight, but destiny may have something else in store.','https://static.tvmaze.com/uploads/images/medium_portrait/0/2451.jpg','2005-09-19',NULL,'2026-07-04T12:48:18.328Z','2026-07-04 12:52:56','2026-07-04 12:52:56',9,24,'2026-07-04T12:48:18.328Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:347','tvmaze','tvmaze:show:347','watching',6,'It''s Always Sunny in Philadelphia','It''s Always Sunny in Philadelphia is an American comedy series about four friends in their late 20s with clear sociopathic tendencies who run an unsuccessful Irish bar, "Paddy''s Pub," in South Philadelphia. The series deals with a variety of controversial topics, including abortion, gun control, physical disabilities, racism, sexism, religion, the Israeli/Palestinian situation, terrorism, transsexuality, slavery, incest, sexual harassment in education, the homeless, statutory rape, drug addiction, pedophilia, child abuse, mental illness, gay rights and dumpster babies.','https://static.tvmaze.com/uploads/images/medium_portrait/583/1459030.jpg','2005-08-04',NULL,'2026-07-04T12:48:19.529Z','2026-07-04 12:52:56','2026-07-04 12:52:56',17,8,'2026-07-04T12:48:19.529Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:84','tvmaze','tvmaze:show:84','watching',7,'Family Guy','Family Guy follows Peter Griffin the endearingly ignorant dad, and his hilariously offbeat family of middle-class New Englanders in Quahog, RI. Lois is Peter''s wife, a stay-at-home mom with no patience for her family''s antics. Then there are their kids: 18-year-old Meg is an outcast at school and the Griffin family punching bag; 13-year-old Chris is a socially awkward teen who doesn''t have a clue about the opposite sex; and one-year-old Stewie is a diabolically clever baby whose burgeoning sexuality is very much a work in progress. Rounding out the Griffin household is Brian the family dog and a ladies'' man who is one step away from AA.','https://static.tvmaze.com/uploads/images/medium_portrait/609/1523259.jpg','1999-01-31',NULL,'2026-07-04T12:48:21.093Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,19,'2026-07-04T12:48:21.093Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:1719','tvmaze','tvmaze:show:1719','completed',9,'Mr. Bean','The first episode of the original Mr. Bean series starring Rowan Atkinson was first broadcast on 1st January 1990. Since then Mr. Bean has become known all over the world. Created by Rowan Atkinson, Richard Curtis and Robin Driscoll, there were only 14 episodes ever made. The original series emerged from Rowan Atkinson''s stage revues of the 1980′s which featured the silent odd-ball. Rowan Atkinson''s comic acting genius has created a highly original work for television. The Mr. Bean series has been sold to 190 territories worldwide and has won an International Emmy and the Golden Rose of Montreux.','https://static.tvmaze.com/uploads/images/medium_portrait/45/113952.jpg','1990-01-01',NULL,'2026-07-04T12:48:22.401Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,14,'2026-07-04T12:48:22.401Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:2000','tvmaze','tvmaze:show:2000','completed',10,'I Dream of Jeannie','I Dream of Jeannie is an American sitcom with a fantasy premise. The show featured a 2,000-year-old genie and an astronaut who becomes her master, with whom she falls in love and eventually marries.','https://static.tvmaze.com/uploads/images/medium_portrait/11/28077.jpg','1965-09-18',NULL,'2026-07-04T12:48:23.399Z','2026-07-04 12:52:56','2026-07-04 12:52:56',5,26,'2026-07-04T12:48:23.399Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:430','tvmaze','tvmaze:show:430','watching',11,'The X-Files','Two FBI agents, Fox Mulder (a believer) and Dana Scully (a skeptic), investigate unexplained cases where the paranormal might be involved while hidden forces work to impede their efforts.','https://static.tvmaze.com/uploads/images/medium_portrait/501/1253511.jpg','1993-09-10',NULL,'2026-07-04T12:48:24.884Z','2026-07-04 12:52:56','2026-07-04 12:52:56',8,21,'2026-07-04T12:48:24.884Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:19','tvmaze','tvmaze:show:19','watching',12,'Supernatural','This haunting series follows the Winchester brothers as they crisscross the lonely and mysterious back roads of the country in their ''67 Chevy Impala, hunting down every evil supernatural force they encounter along the way.','https://static.tvmaze.com/uploads/images/medium_portrait/445/1114097.jpg','2005-09-13',NULL,'2026-07-04T12:48:26.409Z','2026-07-04 12:52:56','2026-07-04 12:52:56',6,5,'2026-07-04T12:48:26.409Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:431','tvmaze','tvmaze:show:431','completed',13,'Friends','Six young (20-something) people from New York City (Manhattan), on their own and struggling to survive in the real world, find the companionship, comfort and support they get from each other to be the perfect antidote to the pressures of life.This average group of buddies goes through massive mayhem, family trouble, past and future romances, fights, laughs, tears and surprises as they learn what it really means to be a friend.','https://static.tvmaze.com/uploads/images/medium_portrait/41/104565.jpg','1994-09-22',NULL,'2026-07-04T12:48:27.730Z','2026-07-04 12:52:56','2026-07-04 12:52:56',10,18,'2026-07-04T12:48:27.730Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:530','tvmaze','tvmaze:show:530','watching',14,'Seinfeld','Seinfeld is the story of a fictionalized version of stand-up comedian Jerry Seinfeld, his life in New York City and his quirky group of friends who join him in wrestling with life''s most perplexing, yet often trivial questions. Often described as "a show about nothing," Seinfeld mines the humor in life''s mundane situations like waiting in line, searching for a lost item, or the trials and tribulations of dating.','https://static.tvmaze.com/uploads/images/medium_portrait/83/207960.jpg','1989-07-05',NULL,'2026-07-04T12:48:29.166Z','2026-07-04 12:52:56','2026-07-04 12:52:56',4,3,'2026-07-04T12:48:29.166Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:539','tvmaze','tvmaze:show:539','completed',15,'The IT Crowd','The comedic misadventures of Roy, Moss and their grifting supervisor Jen, a rag-tag team of IT support workers at a large corporation headed by a hotheaded yuppie.','https://static.tvmaze.com/uploads/images/medium_portrait/4/11405.jpg','2006-02-03',NULL,'2026-07-04T12:48:30.177Z','2026-07-04 12:52:56','2026-07-04 12:52:56',4,6,'2026-07-04T12:48:30.177Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:161','tvmaze','tvmaze:show:161','completed',16,'Dexter','He''s smart, he''s good looking, and he''s got a great sense of humor. He''s Dexter Morgan, everyone''s favorite serial killer. As a Miami forensics expert, he spends his days solving crimes, and nights committing them. But Dexter lives by a strict code of honor that is both his saving grace and lifelong burden. Torn between his deadly compulsion and his desire for true happiness, Dexter is a man in profound conflict with the world and himself.','https://static.tvmaze.com/uploads/images/medium_portrait/498/1246067.jpg','2006-10-01',NULL,'2026-07-04T12:48:31.209Z','2026-07-04 12:52:56','2026-07-04 12:52:56',8,12,'2026-07-04T12:48:31.209Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:134','tvmaze','tvmaze:show:134','plan-to-watch',17,'Heroes','This epic chronicles the lives of ordinary people who discover they possess extraordinary abilities. As a total eclipse casts a shadow across the globe, viewers follow a genetics professor in India whose father''s disappearance leads him to uncover a secret theory—there are people with super powers living among us. A young dreamer tries to convince his politician brother that he can fly. A high school cheerleader learns that she is totally indestructible. A Las Vegas stripper, struggling to make ends meet to support her young son, uncovers that her mirror image has a secret. A prison inmate mysteriously finds himself waking up outside of his cell. A gifted artist, whose drug addiction is destroying his life and the relationship with his girlfriend, can paint the future. A down-on-his-luck beat cop can hear people''s thoughts, including the secrets of a captured terrorist. In Japan, a young man develops a way to stop time through sheer will power. Their ultimate destiny is nothing less than saving the world.','https://static.tvmaze.com/uploads/images/medium_portrait/0/1904.jpg','2006-09-25',NULL,'2026-07-04T12:48:32.535Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,0,'2026-07-04T12:48:32.535Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:168','tvmaze','tvmaze:show:168','plan-to-watch',18,'Chuck','Chuck Bartowski is a computer geek that gets catapulted into a new career as the government''s most vital secret agent. When Chuck opens an e-mail subliminally encoded with government secrets, he unwittingly downloads an entire server of sensitive data into his brain. With the government''s most precious secrets in Chuck''s head, Major John Casey of the National Security Agency assumes the responsibility of protecting him. His partner is the CIA''s top agent, Sarah Walker.','https://static.tvmaze.com/uploads/images/medium_portrait/0/2385.jpg','2007-09-24',NULL,'2026-07-04T12:48:33.566Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,0,'2026-07-04T12:48:33.566Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:3892','tvmaze','tvmaze:show:3892','plan-to-watch',19,'Tin Man','DG is a waitress ripped out of her boring life by a cyclone that drops her into "The O.Z." (Outer Zone). She learns that this new land is beautiful and deadly, since it lies in thrall to Azkadellia, a ruthless sorceress who has seized power. All Azkadellia needs to make her conquest complete is the Emerald of the Eclipse, but the location is buried in DG''s subconscious. As DG follows her dangerous path along the Old Brick Road, she is joined by brainless Glitch, troubled former lawman Wyatt Cain, and terrified oracle Raw.','https://static.tvmaze.com/uploads/images/medium_portrait/19/48719.jpg','2007-12-02',NULL,'2026-07-04T12:48:34.610Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,3,'2026-07-04T12:48:34.610Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:46065','tvmaze','tvmaze:show:46065','watching',229,'One Piece','With his straw hat and ragtag crew, young pirate Monkey D. Luffy goes on an epic voyage for treasure in this live-action adaptation of the popular manga.','https://static.tvmaze.com/uploads/images/medium_portrait/617/1543011.jpg','2023-08-31',NULL,'2026-07-04T12:55:16.921Z','2026-07-04 12:52:56','2026-07-04 12:55:35',2,8,'2026-07-04T12:55:16.921Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:158','tvmaze','tvmaze:show:158','watching',22,'Fringe','When an international flight lands at Boston''s Logan Airport and the passengers and crew have all died grisly deaths, FBI Special Agent Olivia Dunham is called in to investigate. After her partner is nearly killed during the investigation, a desperate Olivia searches frantically for someone to help, leading her to Dr. Walter Bishop, our generation''s Einstein. There''s only one catch: he''s been institutionalized for the last twenty years, and the only way to question him requires pulling his estranged son Peter in to help. When Olivia''s investigation leads her to a manipulative corporate executive, she and her team will discover that what happened on Flight 627 is only a small piece of a larger, more shocking truth and will explore the blurring line between the possible and the impossible.','https://static.tvmaze.com/uploads/images/medium_portrait/0/2245.jpg','2008-09-09',NULL,'2026-07-04T12:48:41.149Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,4,'2026-07-04T12:48:41.149Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:22','tvmaze','tvmaze:show:22','watching',23,'True Blood','True Blood is a horror/drama based on a series of novels called The Southern American Vampires Mysteries. It focuses on Sookie Stackhouse and her various encounters with vampires and other supernatural beings. The show is centred in the small town of Bon Temps in Louisiana. The show focuses heavily on the co-existence of humans with vampires. The show also touches on several other controversial issues involving equal rights, violence, discrimination and religion.','https://static.tvmaze.com/uploads/images/medium_portrait/410/1026956.jpg','2008-09-07',NULL,'2026-07-04T12:48:42.469Z','2026-07-04 12:52:56','2026-07-04 12:52:56',3,3,'2026-07-04T12:48:42.469Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:461','tvmaze','tvmaze:show:461','completed',24,'Legend of the Seeker','In a mythical land, one man, Richard Cypher, discovers his true destiny as he, a mysterious young woman, a wise old wizard and a magical sword are all that stand between the evil tyrant Darken Rahl and his quest for total domination.Based on The Sword of Truth series of books by Terry Goodkind.','https://static.tvmaze.com/uploads/images/medium_portrait/3/9195.jpg','2008-11-01',NULL,'2026-07-04T12:48:43.502Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,22,'2026-07-04T12:48:43.502Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:76','tvmaze','tvmaze:show:76','watching',25,'Sons of Anarchy','Sons of Anarchy is an American television drama series created by Kurt Sutter, about the lives of a close-knit outlaw motorcycle club operating in Charming, a fictional town in California''s Central Valley. The show centers on protagonist Jackson "Jax" Teller (Charlie Hunnam), initially the vice president of the club, who begins questioning the club and himself.','https://static.tvmaze.com/uploads/images/medium_portrait/495/1239905.jpg','2008-09-03',NULL,'2026-07-04T12:48:45.155Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,13,'2026-07-04T12:48:45.155Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:80','tvmaze','tvmaze:show:80','watching',26,'Modern Family','Modern Family revolves around three different types of families (nuclear, step- and same-sex) living in the Los Angeles area, who are interrelated through Jay Pritchett and his children, Claire Dunphy (née Pritchett) and Mitchell Pritchett. Patriarch Jay is remarried to a much younger woman, Gloria Delgado Pritchett (née Ramirez), a passionate Colombian with whom he has an infant son, Fulgencio (Joe) Pritchett, and a son from Gloria''s previous marriage, Manny Delgado.Jay''s daughter Claire was a homemaker, but has returned to the business world. She is now the chief executive of her father''s previous business, Pritchett''s Closets and Blinds. She is married to Phil Dunphy, a realtor and self-professed "cool dad". They have three children: Haley Dunphy, a stereotypical ditzy teenage girl; Alex Dunphy, a nerdy, smart middle child; and Luke Dunphy, the off-beat only son.Jay''s lawyer son Mitchell and his husband Cameron Tucker have one daughter, Lily Tucker-Pritchett. As the name suggests, this family represents a modern-day family, and episodes are comically based on situations which many families encounter in real life.','https://static.tvmaze.com/uploads/images/medium_portrait/359/898320.jpg','2009-09-23',NULL,'2026-07-04T12:48:47.203Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,10,'2026-07-04T12:48:47.203Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:63','tvmaze','tvmaze:show:63','watching',27,'The Vampire Diaries','The Vampire Diaries is a supernatural drama/romance based around Elena Gilbert who falls in love with a 163 year old vampire.Based on a novel series by L.J. Smith.','https://static.tvmaze.com/uploads/images/medium_portrait/271/677698.jpg','2009-09-10',NULL,'2026-07-04T12:48:48.921Z','2026-07-04 12:52:56','2026-07-04 12:52:56',4,23,'2026-07-04T12:48:48.921Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:82','tvmaze','tvmaze:show:82','watching',29,'Game of Thrones','Based on the bestselling book series A Song of Ice and Fire by George R.R. Martin, this sprawling new HBO drama is set in a world where summers span decades and winters can last a lifetime. From the scheming south and the savage eastern lands, to the frozen north and ancient Wall that protects the realm from the mysterious darkness beyond, the powerful families of the Seven Kingdoms are locked in a battle for the Iron Throne. This is a story of duplicity and treachery, nobility and honor, conquest and triumph. In the Game of Thrones, you either win or you die.','https://static.tvmaze.com/uploads/images/medium_portrait/498/1245274.jpg','2011-04-17',NULL,'2026-07-04T12:48:51.308Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,10,'2026-07-04T12:48:51.308Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:716','tvmaze','tvmaze:show:716','completed',30,'Spartacus','Betrayed by his country. Beaten into slavery. Reborn as a warrior. Spartacus is a graphic and visceral account of Rome''s most famous gladiator. When he is separated from the love of his life, Spartacus is forced into the gruesome and bloodthirsty arena, where a grisly death is primetime entertainment. Spartacus must fight for survival, befriend his enemies and play politics in this new world of corruption, violence, sex and fame. He will be seduced by power and tormented by vengeance. But his passion will give him the strength to prevail over every obstacle, in this modern and uninhibited tale of death, honour and endurance.','https://static.tvmaze.com/uploads/images/medium_portrait/354/886339.jpg','2010-01-22',NULL,'2026-07-04T12:48:52.512Z','2026-07-04 12:52:56','2026-07-04 12:52:56',3,10,'2026-07-04T12:48:52.512Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:2189','tvmaze','tvmaze:show:2189','completed',31,'Victorious','Tori Vega''s thrown into the spotlight at a musical showcase and lands a spot at Hollywood Arts, the most prestigious arts high school in the country. At the school, Tori realizes that to fit in, she must stand out!','https://static.tvmaze.com/uploads/images/medium_portrait/441/1102783.jpg','2010-03-27',NULL,'2026-07-04T12:48:53.525Z','2026-07-04 12:52:56','2026-07-04 12:52:56',4,13,'2026-07-04T12:48:53.525Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:516','tvmaze','tvmaze:show:516','watching',32,'Terra Nova','From executive producers Steven Spielberg Peter Chernin, René Echevarria and Brannon Braga comes an epic family adventure 85 million years in the making. Terra Nova follows an ordinary family on an incredible journey back in time to prehistoric Earth as a small part of a daring experiment to save the human race. In the year 2149, the world is dying. The planet is overdeveloped and overcrowded, with the majority of plant and animal life extinct. The future of mankind is in jeopardy, and its only hope for survival is in the distant past. When scientists at the FERMI Particle Accelerator unexpectedly discovered a fracture in time that made it possible to construct a portal into primeval history, the bold notion was born to resettle humanity in the past - a second chance to rebuild civilization and get it right this time.','https://static.tvmaze.com/uploads/images/medium_portrait/394/985664.jpg','2011-09-26',NULL,'2026-07-04T12:48:54.880Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,11,'2026-07-04T12:48:54.880Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:176','tvmaze','tvmaze:show:176','completed',34,'Teen Wolf','Always an outsider and often unnoticed, Scott McCall yearns to be recognized in some small way that takes him out of his typical state of high school anonymity. When his best friend, Stiles, convinces him to go into the woods one night to join a police search for a dead body, Scott encounters a creature in the darkness. Narrowly escaping an attack with a vicious bite in his side, the next day brings strange surprises for Scott at school and his life will never be the same.MTV''s reboot of the classic 1980s cult movie Teen Wolf.','https://static.tvmaze.com/uploads/images/medium_portrait/30/75365.jpg','2011-06-05',NULL,'2026-07-04T12:48:56.688Z','2026-07-04 12:52:56','2026-07-04 12:52:56',6,20,'2026-07-04T12:48:56.688Z');
