INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:5823','tvmaze','tvmaze:show:5823','plan-to-watch',36,'Transformers: Prime','Set in the timeframe after the novels and video games preceding the television series (also known as the Aligned Continuity), Prime began with a five-part mini-series titled "Darkness Rising", which served to introduce the main characters and provide a back story on the Transformers and their war.','https://static.tvmaze.com/uploads/images/medium_portrait/397/994964.jpg','2010-11-26',NULL,'2026-07-04T12:48:59.060Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,9,'2026-07-04T12:48:59.060Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:10','tvmaze','tvmaze:show:10','completed',37,'Grimm','Grimm is a drama series inspired by the classic Grimm Brothers'' Fairy Tales. After Portland homicide detective Nick Burkhardt discovers he''s descended from an elite line of criminal profilers known as "Grimms", he increasingly finds his responsibilities as a detective at odds with his new responsibilities as a Grimm.','https://static.tvmaze.com/uploads/images/medium_portrait/69/174906.jpg','2011-10-28',NULL,'2026-07-04T12:49:00.090Z','2026-07-04 12:52:56','2026-07-04 12:52:56',6,13,'2026-07-04T12:49:00.090Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:124','tvmaze','tvmaze:show:124','watching',38,'2 Broke Girls','2 Broke Girls is a comedy about two young women waitressing at a greasy spoon diner who strike up an unlikely friendship in the hopes of launching a successful business - if only they can raise the cash. Sassy, streetwise Max Black works two jobs just to get by, one of which is waiting tables during the night shift at the retro-hip Williamsburg Diner. Sophisticated Caroline Channing is an uptown trust fund princess who''s having a run of bad luck that forces her to reluctantly give waitressing a shot. At first, Max sees Caroline as yet another in a long line of inept servers she must cover for, but she''s surprised to find that Caroline has as much substance as she does style.When Caroline discovers Max''s knack for baking amazing cupcakes, she sees a lucrative future for them, but first they need to raise the start-up money. While they save their tips, they''ll stay at the restaurant, working with Oleg, an overly flirtatious Russian cook; Earl, a 75-year-old kool-kat cashier; and Han Lee, the new, eager-to-please owner of the diner. Working together, these two broke girls living in one expensive city might just find the perfect recipe for their big break.','https://static.tvmaze.com/uploads/images/medium_portrait/63/158548.jpg','2011-09-19',NULL,'2026-07-04T12:49:01.117Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,7,'2026-07-04T12:49:01.117Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:1879','tvmaze','tvmaze:show:1879','watching',40,'Femme Fatales','Inspired by and styled in the tradition of pulp stories, film noir and graphic novels, this provocative hit series tells the stories of dangerous women who find extraordinary ways of coping with their problems, channeling their survival instincts and bringing out their inner guile.','https://static.tvmaze.com/uploads/images/medium_portrait/405/1012797.jpg','2011-05-13',NULL,'2026-07-04T12:49:03.178Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,3,'2026-07-04T12:49:03.178Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:30','tvmaze','tvmaze:show:30','watching',41,'American Horror Story','American Horror Story is an horror television anthology series. Each season is conceived as a self-contained miniseries, following a disparate set of characters and settings, and a storyline with its own beginning, middle, and end. While some actors appear for more than one year, they play completely different roles in each season.','https://static.tvmaze.com/uploads/images/medium_portrait/473/1183640.jpg','2011-10-05',NULL,'2026-07-04T12:49:04.289Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,9,'2026-07-04T12:49:04.289Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:13162','tvmaze','tvmaze:show:13162','completed',42,'3%','A world divided into progress and devastation. The link between the two sides - Offshore and Inland - is a rigorous and painstaking system called The Process. Everyone in Inland has a chance to go through The Process to live a better life in Offshore. But only 3% make it through.','https://static.tvmaze.com/uploads/images/medium_portrait/208/520741.jpg','2016-11-25',NULL,'2026-07-04T12:49:05.739Z','2026-07-04 12:52:56','2026-07-04 12:52:56',4,7,'2026-07-04T12:49:05.739Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:305','tvmaze','tvmaze:show:305','watching',43,'Black Mirror','Over the last ten years, technology has transformed almost every aspect of our lives before we''ve had time to stop and question it. In every home; on every desk; in every palm - a plasma screen; a monitor; a smartphone--a black mirror of our 21st Century existence. Black Mirror is a contemporary British re-working of The Twilight Zone with stories that tap into the collective unease about our modern world.','https://static.tvmaze.com/uploads/images/medium_portrait/564/1411764.jpg','2011-12-04',NULL,'2026-07-04T12:49:06.924Z','2026-07-04 12:52:56','2026-07-04 12:52:56',7,6,'2026-07-04T12:49:06.924Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:3182','tvmaze','tvmaze:show:3182','completed',44,'American Gods','American Gods follows Shadow Moon, a man serving three years in prison who is given an early release. Shadow Moon is hired as Mr. Wednesday''s bodyguard and finds himself in a hidden world where a battle is brewing between the Old Gods and the New Gods.','https://static.tvmaze.com/uploads/images/medium_portrait/289/722622.jpg','2017-04-30',NULL,'2026-07-04T12:49:09.531Z','2026-07-04 12:52:56','2026-07-04 12:52:56',3,10,'2026-07-04T12:49:09.531Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:194','tvmaze','tvmaze:show:194','completed',45,'Hannibal','Criminal profiler Will Graham is tasked by FBI agent Jack Crawford, the head of Behavioral Sciences, to help investigate the disappearances of eight young girls across Minnesota. Graham and Crawford''s team investigate several subsequent murders, while also trying to catch the Chesapeake Ripper. With the investigation weighing heavily on Graham, Crawford decides to have him supervised by psychiatrist Dr. Hannibal Lecter, who, unbeknownst to them, is the Chesapeake Ripper himself, actively seeking to derail the investigation.','https://static.tvmaze.com/uploads/images/medium_portrait/498/1246088.jpg','2013-04-04',NULL,'2026-07-04T12:49:10.766Z','2026-07-04 12:52:56','2026-07-04 12:52:56',3,13,'2026-07-04T12:49:10.766Z');
