INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:182','tvmaze','tvmaze:show:182','watching',49,'Black Sails','1715. The Golden Age of Piracy. New Providence Island is a lawless territory, controlled by history''s most notorious pirate captains. The most feared is Captain Flint.As the British Navy returns to redeem their land and exterminate Flint and his crew, another side of him emerges. Captain Flint aligns himself with Eleanor Guthrie, daughter of the local kingpin, to hunt the ultimate prize and ensure their survival.Many opponents stand in their way: rival captains, jealous of Flint''s power; Eleanor''s ambitious and intrusive father; and a young sailor recently recruited onto Flint''s crew, John Silver, who constantly undermines his captain''s agenda.','https://static.tvmaze.com/uploads/images/medium_portrait/501/1253514.jpg','2014-01-25',NULL,'2026-07-04T12:49:14.521Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,4,'2026-07-04T12:49:14.521Z');
