INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:69','tvmaze','tvmaze:show:69','plan-to-watch',52,'The Blacklist','The Blacklist is a crime drama involving a former government agent who turned into a high-profile criminal turning himself in to the FBI offering to help catch criminals.','https://static.tvmaze.com/uploads/images/medium_portrait/445/1113538.jpg','2013-09-23',NULL,'2026-07-04T12:49:17.604Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,0,'2026-07-04T12:49:17.604Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:62','tvmaze','tvmaze:show:62','completed',53,'The Originals','The Originals is a spin-off show from the supernatural drama The Vampire Diaries. It is based in the city of New Orleans where the originals represent the original vampires. The show is primarily based around conflict between vampires, werewolves and witches in the city.','https://static.tvmaze.com/uploads/images/medium_portrait/271/678632.jpg','2013-10-03',NULL,'2026-07-04T12:49:19.239Z','2026-07-04 12:52:56','2026-07-04 12:52:56',5,13,'2026-07-04T12:49:19.239Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:919','tvmaze','tvmaze:show:919','watching',54,'Attack on Titan','Known in Japan as Shingeki no Kyojin, many years ago, the last remnants of humanity were forced to retreat behind the towering walls of a fortified city to escape the massive, man-eating Titans that roamed the land outside their fortress. Only the heroic members of the Scouting Legion dared to stray beyond the safety of the walls – but even those brave warriors seldom returned alive. Those within the city clung to the illusion of a peaceful existence until the day that dream was shattered, and their slim chance at survival was reduced to one horrifying choice: kill – or be devoured!','https://static.tvmaze.com/uploads/images/medium_portrait/476/1191684.jpg','2013-04-07',NULL,'2026-07-04T12:49:20.566Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,6,'2026-07-04T12:49:20.566Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:202','tvmaze','tvmaze:show:202','completed',55,'Almost Human','Almost Human is an action-packed police drama set 35 years in the future, when police officers are partnered with highly evolved human-like androids. The year is 2048. Meet John Kennex a cop who survived one of the most catastrophic attacks ever made against the police department. After waking up from a 17-month coma, he can''t remember much - except that his partner was killed; his girlfriend, Anna Moore, left him after the attack; and he lost one of his legs and is now outfitted with a highly sophisticated synthetic appendage. Suffering from depression, mental atrophy, trauma-onset OCD, PTSD and the "psychological rejection of his synthetic body part," John returns to work at the behest of longtime ally Captain Sandra Maldonado. By mandate, every cop must partner with a robot. And despite his passionate aversion to androids, John is paired up with a battle-ready MX-43. But he abruptly terminates his partnership after the robot discovers incriminating information about him. So technician Rudy Lom introduces John to Dorian, a discontinued android with unexpected emotional responses. Although such responses were deemed flaws, it is in these "flaws" that John relates to Dorian most. After all, John is part-machine now, and Dorian is part-human. John and Dorian''s understanding of each other not only complements them, it connects them. As he adjusts to working with his new partner, John also must learn to get along with his new colleagues, including the eager and somewhat starstruck Detective Valerie Stahl and the distrustful Detective Richard Paul, who does not welcome John back with open arms. Almost Human will follow the week-to-week missions of John and Dorian, as they fight crime across this futuristic landscape, while the mysteries surrounding his attack and the larger mythology of this new world unfold.','https://static.tvmaze.com/uploads/images/medium_portrait/1/3020.jpg','2013-11-17',NULL,'2026-07-04T12:49:21.905Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,13,'2026-07-04T12:49:21.905Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:1367','tvmaze','tvmaze:show:1367','completed',56,'Sense8','A group of people around the world are suddenly linked mentally, and must find a way to survive being hunted by those who see them as a threat to the world''s order.','https://static.tvmaze.com/uploads/images/medium_portrait/154/387311.jpg','2015-06-05',NULL,'2026-07-04T12:49:23.636Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,12,'2026-07-04T12:49:23.636Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:6','tvmaze','tvmaze:show:6','watching',57,'The 100','Ninety-seven years ago, nuclear Armageddon decimated planet Earth, destroying civilization. The only survivors were the 400 inhabitants of 12 international space stations that were in orbit at the time. Three generations have been born in space, the survivors now number 4,000, and resources are running out on their dying "Ark" - the 12 stations now linked together and repurposed to keep the survivors alive. Draconian measures including capital punishment and population control are the order of the day, as the leaders of the Ark take ruthless steps to ensure their future, including secretly exiling a group of 100 juvenile prisoners to the Earth''s surface to test whether it''s habitable.','https://static.tvmaze.com/uploads/images/medium_portrait/477/1194981.jpg','2014-03-19',NULL,'2026-07-04T12:49:24.660Z','2026-07-04 12:52:56','2026-07-04 12:52:56',7,8,'2026-07-04T12:49:24.660Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:377','tvmaze','tvmaze:show:377','plan-to-watch',58,'The Musketeers','A thrilling world of action, adventure and romance inspired by Dumas'' legendary characters.On the streets of 17th century Paris, law and order is more a fledgling idea than reality, and the Musketeers, Athos, Aramis and Porthos, are far more than merely royal bodyguards for King Louis XIII; they are inseparable, loyal unto death and committed to upholding justice. Together, this crack team of highly trained soldiers fight for honour, for valour, for love, and just for the pure thrill of it.','https://static.tvmaze.com/uploads/images/medium_portrait/2/5545.jpg','2014-01-19',NULL,'2026-07-04T12:49:25.691Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,4,'2026-07-04T12:49:25.691Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:21','tvmaze','tvmaze:show:21','completed',59,'The Last Ship','Their mission is simple: Find a cure. Stop the virus. Save the world. When a global pandemic wipes out eighty percent of the planet''s population, the crew of a lone and unaffected Navy destroyer, the USS Nathan James, must find a way to pull humanity from the brink of extinction.','https://static.tvmaze.com/uploads/images/medium_portrait/164/412464.jpg','2014-06-22',NULL,'2026-07-04T12:49:26.695Z','2026-07-04 12:52:56','2026-07-04 12:52:56',5,10,'2026-07-04T12:49:26.695Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:5','tvmaze','tvmaze:show:5','watching',60,'True Detective','Touch darkness and darkness touches you back. True Detective centers on troubled cops and the investigations that drive them to the edge. Each season features a new cast and a new case.True Detective is an American anthology crime drama television series created and written by Nic Pizzolatto.','https://static.tvmaze.com/uploads/images/medium_portrait/490/1226764.jpg','2014-01-12',NULL,'2026-07-04T12:49:27.726Z','2026-07-04 12:52:56','2026-07-04 12:52:56',4,6,'2026-07-04T12:49:27.726Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:15','tvmaze','tvmaze:show:15','completed',61,'Constantine','Based on the wildly popular comic book series "Hellblazer" from DC Comics, seasoned demon hunter and master of the occult John Constantine is armed with a ferocious knowledge of the dark arts and a wickedly naughty wit. He fights the good fight - or at least he did. With his soul already damned to hell, he''s decided to abandon his campaign against evil until a series of events thrusts him back into the fray, and he''ll do whatever it takes to protect the innocent. With the balance of good and evil on the line‎, Constantine will use his skills to travel the country, find the supernatural terrors that threaten our world and send them back where they belong. After that, who knows... maybe there''s hope for him and his soul after all.','https://static.tvmaze.com/uploads/images/medium_portrait/0/154.jpg','2014-10-24',NULL,'2026-07-04T12:49:28.667Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,13,'2026-07-04T12:49:28.667Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:11','tvmaze','tvmaze:show:11','completed',62,'Gotham','The good. The evil. The beginning.Everyone knows the name Commissioner Gordon. He is one of the crime world''s greatest foes, a man whose reputation is synonymous with law and order. But what is known of Gordon''s story and his rise from rookie detective to Police Commissioner? What did it take to navigate the multiple layers of corruption that secretly ruled Gotham City, the spawning ground of the world''s most iconic villains? And what circumstances created them – the larger-than-life personas who would become Catwoman, The Penguin, The Riddler, Two-Face and The Joker?Gotham is an origin story of the great DC Comics Super-Villains and vigilantes, revealing an entirely new chapter that has never been told. It follows one cop''s rise through a dangerously corrupt city teetering between good and evil, and chronicles the birth of one of the most popular super heroes of our time.','https://static.tvmaze.com/uploads/images/medium_portrait/189/474715.jpg','2014-09-22',NULL,'2026-07-04T12:49:29.781Z','2026-07-04 12:52:56','2026-07-04 12:52:56',5,12,'2026-07-04T12:49:29.781Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:216','tvmaze','tvmaze:show:216','watching',63,'Rick and Morty','Rick is a mentally gifted, but sociopathic and alcoholic scientist and a grandfather to Morty; an awkward, impressionable, and somewhat spineless teenage boy. Rick moves into the family home of Morty, where he immediately becomes a bad influence.','https://static.tvmaze.com/uploads/images/medium_portrait/626/1566363.jpg','2013-12-02',NULL,'2026-07-04T12:49:30.798Z','2026-07-04 12:52:56','2026-07-04 12:52:56',9,5,'2026-07-04T12:49:30.798Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:374','tvmaze','tvmaze:show:374','plan-to-watch',64,'Inside No. 9','An anthology of darkly comic twisted tales by Steve Pemberton and Reece Shearsmith, each one taking place behind a door marked ''number 9''.','https://static.tvmaze.com/uploads/images/medium_portrait/62/156641.jpg','2014-02-05',NULL,'2026-07-04T12:49:31.828Z','2026-07-04 12:52:56','2026-07-04 12:52:56',4,6,'2026-07-04T12:49:31.828Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:143','tvmaze','tvmaze:show:143','completed',65,'Silicon Valley','In the high-tech gold rush of modern Silicon Valley, the people most qualified to succeed are the least capable of handling success. From Mike Judge comes this satire about a programmer whose game-changing algorithm becomes the subject of a valley-wide bidding war.','https://static.tvmaze.com/uploads/images/medium_portrait/215/538434.jpg','2014-04-06',NULL,'2026-07-04T12:49:33.361Z','2026-07-04 12:52:56','2026-07-04 12:52:56',6,7,'2026-07-04T12:49:33.361Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:1731','tvmaze','tvmaze:show:1731','plan-to-watch',66,'Olympus','The 13-part mythological drama series Olympus takes viewers into the action-packed world of humans, Gods and monsters. Starring Matt Frewer (Max Headroom, Orphan Black), Sonita Henry (Star Trek, The Fifth Element), Cas Anvar (Argo, The Expanse) and Graham Shiels (Guardians of the Galaxy, Thor: Dark World), the gripping series captures the dangerous courage of a few brave men and women who banished the Gods to the realm of the unconscious - a place they called the Underworld or the Kingdom of Hades.','https://static.tvmaze.com/uploads/images/medium_portrait/9/24091.jpg','2015-04-02',NULL,'2026-07-04T12:49:34.391Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,0,'2026-07-04T12:49:34.391Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:1589','tvmaze','tvmaze:show:1589','completed',67,'iZombie','Olivia "Liv" Moore is a rosy-cheeked, disciplined, over-achieving medical resident who had her life path completely mapped out... until the night she attended a party that unexpectedly turned into a zombie feeding frenzy. As one of the newly undead, Liv has devised a way to resist her baser urges to devour fresh human brains--she''s taken a job in the Seattle coroner''s office.In this appropriately dead-end job, she can secretly snack on the brains of the many Jane and John Doe corpses that make a final stop in the morgue. Liv remains resigned to an eternity without hope or purpose, until she realizes that with every brain she consumes, she retains a portion of that person''s memories, and she begins to experience visions from the point of view of the murder victims. It''s not the same as being alive again, but at least she can find purpose in her undead existence by helping to solve the murders of those who are indeed fully dead.','https://static.tvmaze.com/uploads/images/medium_portrait/477/1194487.jpg','2015-03-17',NULL,'2026-07-04T12:49:35.714Z','2026-07-04 12:52:56','2026-07-04 12:52:56',5,13,'2026-07-04T12:49:35.714Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:60522','tvmaze','tvmaze:show:60522','completed',262,'The Recruit','The Recruit follows Owen Hendricks, a fledgling lawyer at the CIA who becomes enmeshed in dangerous international power politics when a former asset threatens to expose the agency.','https://static.tvmaze.com/uploads/images/medium_portrait/550/1376612.jpg','2022-12-16',NULL,'2026-07-04T12:55:22.454Z','2026-07-04 12:52:56','2026-07-04 12:55:35',2,6,'2026-07-04T12:55:22.454Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:2029','tvmaze','tvmaze:show:2029','plan-to-watch',69,'American Crime Story','This anthology series dramatizes historic criminal cases in the U.S.','https://static.tvmaze.com/uploads/images/medium_portrait/401/1004505.jpg','2016-02-02',NULL,'2026-07-04T12:49:37.772Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,0,'2026-07-04T12:49:37.772Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:1871','tvmaze','tvmaze:show:1871','watching',70,'Mr. Robot','Mr. Robot follows Elliot, a young programmer who works as a cyber-security engineer by day and as a vigilante hacker by night. Elliot finds himself at a crossroads when the mysterious leader of an underground hacker group recruits him to destroy the firm he is paid to protect. Compelled by his personal beliefs, Elliot struggles to resist the chance to take down the multinational CEOs he believes are running (and ruining) the world.','https://static.tvmaze.com/uploads/images/medium_portrait/211/528026.jpg','2015-06-24',NULL,'2026-07-04T12:49:38.785Z','2026-07-04 12:52:56','2026-07-04 12:52:56',3,10,'2026-07-04T12:49:38.785Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:1363','tvmaze','tvmaze:show:1363','completed',71,'Humans','Humans is set in a parallel present where the latest must-have gadget for any busy family is a Synth – a highly-developed robotic servant eerily similar to its live counterpart. In the hope of transforming the way they live, one strained suburban family purchases a refurbished synth only to discover that sharing life with a machine has far-reaching and chilling consequences.','https://static.tvmaze.com/uploads/images/medium_portrait/182/457420.jpg','2015-06-14',NULL,'2026-07-04T12:49:40.330Z','2026-07-04 12:52:56','2026-07-04 12:52:56',3,8,'2026-07-04T12:49:40.330Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:1855','tvmaze','tvmaze:show:1855','watching',73,'Blindspot','A beautiful woman, with no memories of her past, is found naked in Times Square with her body fully covered in intricate tattoos. Her discovery sets off a vast and complex mystery that immediately ignites the attention of the FBI, which begins to follow the road map on her body into a larger conspiracy of crime, while bringing her closer to discovering the truth about her identity.','https://static.tvmaze.com/uploads/images/medium_portrait/486/1215674.jpg','2015-09-21',NULL,'2026-07-04T12:49:42.578Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,13,'2026-07-04T12:49:42.578Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:1859','tvmaze','tvmaze:show:1859','completed',74,'Lucifer','The Devil has come to Los Angeles…Based upon the characters created by Neil Gaiman, Sam Kieth and Mike Dringenberg for DC Entertainment''s Vertigo imprint, Lucifer is the story of the original fallen angel. Bored and unhappy as the Lord of Hell, Lucifer Morningstar has abandoned his throne and retired to L.A., where he owns Lux, an upscale nightclub.Charming, charismatic and devilishly handsome, Lucifer is enjoying his retirement, indulging in a few of his favorite things--wine, women and song-–when a beautiful pop star is brutally murdered outside of Lux. For the first time in roughly 10 billion years, he feels something awaken deep within him as a result of this murder. Compassion? Sympathy? The very thought disturbs him--as well as his best friend and confidante, Mazkeen aka Maze, a fierce demon in the form of a beautiful young woman.','https://static.tvmaze.com/uploads/images/medium_portrait/346/865655.jpg','2016-01-25',NULL,'2026-07-04T12:49:43.607Z','2026-07-04 12:52:56','2026-07-04 12:52:56',6,10,'2026-07-04T12:49:43.607Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:1851','tvmaze','tvmaze:show:1851','watching',75,'DC''s Legends of Tomorrow','When heroes alone are not enough... the world needs legends. Having seen the future, one he will desperately try to prevent from happening, time-traveling rogue Rip Hunter is tasked with assembling a disparate group of both heroes and villains to confront an unstoppable threat - one in which not only is the planet at stake, but all of time itself. Can this ragtag team defeat an immortal threat unlike anything they have ever known?','https://static.tvmaze.com/uploads/images/medium_portrait/315/787584.jpg','2016-01-21',NULL,'2026-07-04T12:49:44.729Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,13,'2026-07-04T12:49:44.729Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:1804','tvmaze','tvmaze:show:1804','plan-to-watch',76,'The Man in the High Castle','The Man in the High Castle is a startling depiction of an alternate history as imagined by author Philip K. Dick in his best-selling novel; a world in which Nazi Germany and Japan were victorious in World War II. The year is 1962 and the Axis Powers occupy the United States, where fascism rules and the few surviving Jews hide under assumed names.','https://static.tvmaze.com/uploads/images/medium_portrait/216/541957.jpg','2015-01-15',NULL,'2026-07-04T12:49:45.960Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,0,'2026-07-04T12:49:45.960Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:2158','tvmaze','tvmaze:show:2158','watching',77,'Shadowhunters: The Mortal Instruments','Based on the bestselling young adult fantasy book series The Mortal Instruments by Cassandra Clare, Shadowhunters follows 18-year-old Clary Fray, who finds out on her birthday that she is not who she thinks she is but rather comes from a long line of Shadowhunters - human-angel hybrids who hunt down demons. When her mother, Jocelyn, is kidnapped, Clary is thrown into the world of demon hunting with mysterious Shadowhunter Jace and her best friend, Simon. Now living among faeries, warlocks, vampires and werewolves, Clary begins a journey of self-discovery as she learns more about her past and what her future may hold.','https://static.tvmaze.com/uploads/images/medium_portrait/181/454353.jpg','2016-01-12',NULL,'2026-07-04T12:49:47.771Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,6,'2026-07-04T12:49:47.771Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:1371','tvmaze','tvmaze:show:1371','watching',78,'Westworld','Westworld is a dark odyssey about the dawn of artificial consciousness and the evolution of sin. Set at the intersection of the near future and the reimagined past, it explores a world in which every human appetite, no matter how noble or depraved, can be indulged.','https://static.tvmaze.com/uploads/images/medium_portrait/445/1113927.jpg','2016-10-02',NULL,'2026-07-04T12:49:49.156Z','2026-07-04 12:52:56','2026-07-04 12:52:56',3,8,'2026-07-04T12:49:49.156Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:3144','tvmaze','tvmaze:show:3144','completed',79,'Preacher','Based on the popular cult comic book franchise of the same name, Preacher is a supernatural, twisted and darkly comedic drama that follows a West Texas preacher named Jesse Custer, who is inhabited by a mysterious entity that causes him to develop a highly unusual power. Jesse, his badass ex-girlfriend Tulip and an Irish vagabond named Cassidy come together, and when they do, they are thrust into a crazy world populated by a cast of characters from Heaven, Hell and everywhere in between.','https://static.tvmaze.com/uploads/images/medium_portrait/205/514552.jpg','2016-05-22',NULL,'2026-07-04T12:49:50.466Z','2026-07-04 12:52:56','2026-07-04 12:52:56',4,10,'2026-07-04T12:49:50.466Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:5529','tvmaze','tvmaze:show:5529','completed',80,'11.22.63','Imagine having the power to change history. Would you journey down the "rabbit hole"? This event series follows Jake Epping, an ordinary high school teacher, presented with the unthinkable mission of traveling back in time to prevent the assassination of John F. Kennedy on November 22, 1963. Jake travels to the past in order to solve the most enduring mystery of the 20th century: who killed JFK, and could it have been stopped? But as Jake will learn, the past does not want to be changed. And trying to divert the course of history may prove fatal.','https://static.tvmaze.com/uploads/images/medium_portrait/63/157675.jpg','2016-02-15',NULL,'2026-07-04T12:49:51.997Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,8,'2026-07-04T12:49:51.997Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:2993','tvmaze','tvmaze:show:2993','watching',81,'Stranger Things','When a young boy vanishes, a small town uncovers a mystery involving secret experiments, terrifying supernatural forces and one strange little girl.','https://static.tvmaze.com/uploads/images/medium_portrait/595/1489169.jpg','2016-07-15',NULL,'2026-07-04T12:49:53.788Z','2026-07-04 12:52:56','2026-07-04 12:52:56',4,9,'2026-07-04T12:49:53.788Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:3080','tvmaze','tvmaze:show:3080','plan-to-watch',82,'Big Little Lies','In the tranquil seaside town of Monterey, California, nothing is quite as it seems. Doting moms, successful husbands, adorable children, beautiful homes: What lies will be told to keep their perfect worlds from unraveling?Told through the eyes of three mothers – Madeline, Celeste and Jane – Big Little Lies paints a picture of a town fueled by rumors and divided into the haves and have-nots, exposing the conflicts, secrets and betrayals that compromise relationships between husbands and wives, parents and children, and friends and neighbors.','https://static.tvmaze.com/uploads/images/medium_portrait/196/490640.jpg','2017-02-19',NULL,'2026-07-04T12:49:54.880Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,0,'2026-07-04T12:49:54.880Z');
