INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:2790','tvmaze','tvmaze:show:2790','watching',84,'The Good Place','The Good Place is a smart, unique comedy about what makes a good person. The show follows Eleanor Shellstrop, an ordinary woman who enters the afterlife and, thanks to some kind of error, is sent to the Good Place instead of the Bad Place, which is definitely where she belongs. While hiding in plain sight from Michael, the wise architect of the Good Place (who doesn''t know he''s made a mistake), she''s determined to shed her old way of living and discover the awesome (or, at least, the pretty good) person within.','https://static.tvmaze.com/uploads/images/medium_portrait/395/989291.jpg','2016-09-19',NULL,'2026-07-04T12:49:56.911Z','2026-07-04 12:52:56','2026-07-04 12:52:56',4,13,'2026-07-04T12:49:56.911Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:2793','tvmaze','tvmaze:show:2793','watching',86,'Powerless','Emily is a spunky young insurance adjuster specializing in regular-people coverage against damage caused by the crime-fighting superheroes. It''s when she stands up to one of these larger-than-life figures (after an epic battle messes with her commute) that she accidentally becomes a cult "hero" in her own right … even if it''s just to her group of lovably quirky co-workers. Now, while she navigates her normal, everyday life against an explosive backdrop, Emily might just discover that being a hero doesn''t always require superpowers.','https://static.tvmaze.com/uploads/images/medium_portrait/91/229096.jpg','2017-02-02',NULL,'2026-07-04T12:49:59.573Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,12,'2026-07-04T12:49:59.573Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:5495','tvmaze','tvmaze:show:5495','plan-to-watch',87,'Lethal Weapon','Combining action and drama with ride-or-die friendship and humor, Lethal Weapon reimagines the hit movie franchise, as it follows classic cop duo Riggs and Murtaugh, who work a crime-ridden beat in modern-day Los Angeles. Grief-stricken after the loss of his young wife and unborn child, ex-Navy SEAL-turned-detective Martin Riggs moves to California to "start over" at the LAPD. He''s paired up with Roger Murtaugh, who''s just coming back to the job after a near-fatal heart attack. Riggs'' penchant for diving headfirst into the line of fire immediately clashes with Murtaugh''s prudent, by-the-book technique.','https://static.tvmaze.com/uploads/images/medium_portrait/168/421354.jpg','2016-09-21',NULL,'2026-07-04T12:50:00.606Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,0,'2026-07-04T12:50:00.606Z');
