INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:2175','tvmaze','tvmaze:show:2175','completed',90,'Marvel''s Iron Fist','After his family meets a tragic fate while on expedition in China, a young Rand is adopted by the people of the mystical lost city of K''un-Lun, where he''s taught a magical fighting style. Years later, he returns to New York to fight crime.','https://static.tvmaze.com/uploads/images/medium_portrait/164/412207.jpg','2017-03-17',NULL,'2026-07-04T12:50:02.851Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,10,'2026-07-04T12:50:02.851Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:22928','tvmaze','tvmaze:show:22928','completed',92,'Marvel''s Inhumans','Marvel''s Inhumans explores the never-before-told epic adventure of the royal family including Black Bolt, the enigmatic, commanding King of the Inhumans, with a voice so powerful that the slightest whisper can destroy a city. After the Royal Family of Inhumans is splintered by a military coup, they barely escape to Hawaii where they are greeted with surprising interactions with the lush world and humanity around them. Now they must find a way to reunite with each other and return to their home before their way of life is destroyed forever.','https://static.tvmaze.com/uploads/images/medium_portrait/394/985756.jpg','2017-09-29',NULL,'2026-07-04T12:50:04.333Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,8,'2026-07-04T12:50:04.333Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:6393','tvmaze','tvmaze:show:6393','completed',93,'Legion','Legion introduces the story of David Haller: Since he was a teenager, David has struggled with mental illness. Diagnosed as schizophrenic, David has been in and out of psychiatric hospitals for years. But after a strange encounter with a fellow patient, he''s confronted with the possibility that the voices he hears and the visions he sees might be real. He''s based on the Marvel comics character Legion, the son of X-Men founder Charles Xavier (played by Patrick Stewart and James McAvoy in the films), first introduced in 1985.','https://static.tvmaze.com/uploads/images/medium_portrait/201/504677.jpg','2017-02-08',NULL,'2026-07-04T12:50:05.312Z','2026-07-04 12:52:56','2026-07-04 12:52:56',3,8,'2026-07-04T12:50:05.312Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:7194','tvmaze','tvmaze:show:7194','completed',94,'13 Reasons Why','13 Reasons Why is based on the New York Times bestselling YA book by Jay Asher, was created by Pulitzer Prize and Tony Award winner Brian Yorkey, who also wrote the pilot. 13 Reasons Why is the story of Hannah Baker, a high schooler who commits suicide. Clay receives a box of tapes from Hannah, his late classmate and crush after she kills herself. On the tapes, which get passed along to other students based on Hannah''s instructions, Hannah reveals the 13 reasons why she took her own life.','https://static.tvmaze.com/uploads/images/medium_portrait/258/646815.jpg','2017-03-31',NULL,'2026-07-04T12:50:06.845Z','2026-07-04 12:52:56','2026-07-04 12:52:56',4,10,'2026-07-04T12:50:06.845Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:36021','tvmaze','tvmaze:show:36021','plan-to-watch',108,'Space Island One','Space Island One is set on a station in Earths orbit named Unity and follows the crew as they live and work for the ever demanding needs of the company. Unity Station is a subsection of a large research company on Earth and houses a crew of seven dedicated scientists.','https://static.tvmaze.com/uploads/images/medium_portrait/152/381310.jpg','1998-01-07',NULL,'2026-07-04T12:50:22.409Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,0,'2026-07-04T12:50:22.409Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:25948','tvmaze','tvmaze:show:25948','completed',96,'The Gifted','The Gifted tells the story of a suburban couple whose ordinary lives are rocked by the sudden discovery that their children possess mutant powers. Forced to go on the run from a hostile government, the family joins up with an underground network of mutants and must fight to survive.','https://static.tvmaze.com/uploads/images/medium_portrait/165/414995.jpg','2017-10-02',NULL,'2026-07-04T12:50:08.904Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,16,'2026-07-04T12:50:08.904Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:10822','tvmaze','tvmaze:show:10822','completed',98,'MINDHUNTER','MINDHUNTER is based on the 1996 book Mind Hunter: Inside the FBI''s Elite Serial Crime Unit, by former special agent John Douglas and Mark Olshaker. For years, Douglas pursued some of the most notorious serial killers and rapists, developing profiling techniques to catch them. The book goes behind the scenes of some of his highest-profile cases, including the man who hunted prostitutes in Alaska, the Atlanta child murderer, and Seattle''s Green River killer. To hone in his profiling methods Douglas interviewed and studied a skew of serial killers. Several book and TV characters have been based in part on him, including Jack Crawford in Thomas Harris'' The Silence of the Lambs, Will Graham on Hannibal and Jason Gideon on Criminal Minds.','https://static.tvmaze.com/uploads/images/medium_portrait/501/1253490.jpg','2017-10-13',NULL,'2026-07-04T12:50:10.245Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,9,'2026-07-04T12:50:10.245Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:26020','tvmaze','tvmaze:show:26020','watching',99,'Young Sheldon','For young Sheldon Cooper, it isn''t easy growing up in East Texas. Being a once-in-a-generation mind capable of advanced mathematics and science isn''t always helpful in a land where church and football are king. And while the vulnerable, gifted and somewhat naïve Sheldon deals with the world, his very normal family must find a way to deal with him. His father, George, is struggling to find his way as a high school football coach and as father to a boy he doesn''t understand. Sheldon''s mother, Mary, fiercely protects and nurtures her son in a town where he just doesn''t fit in. Sheldon''s older brother, Georgie, does the best he can in high school, but it''s tough to be cool when you''re in the same classes with your odd younger brother. Sheldon''s twin sister, Missy, sometimes resents all the attention Sheldon gets, but also remains the one person who can reliably tell Sheldon the truth. Finally, there''s Sheldon''s beloved Meemaw, his foul-mouthed, hard-drinking Texas grandmother who is very supportive of her grandson and his unique gifts. For 12 years on The Big Bang Theory, audiences have come to know the iconic, eccentric, and extraordinary Sheldon Cooper. This single-camera, half-hour comedy allows us the chance to meet him in childhood, as he embarks on his innocent, awkward, and hopeful journey toward the man he will become.','https://static.tvmaze.com/uploads/images/medium_portrait/513/1283060.jpg','2017-09-25',NULL,'2026-07-04T12:50:11.571Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,22,'2026-07-04T12:50:11.571Z');
