INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:20172','tvmaze','tvmaze:show:20172','completed',104,'Marvel''s Runaways','Every teenager thinks their parents are evil. What if you found out they actually were? Marvel''s Runaways is the story of six diverse teenagers who can barely stand each other but who must unite against a common foe – their parents.','https://static.tvmaze.com/uploads/images/medium_portrait/230/577058.jpg','2017-11-21',NULL,'2026-07-04T12:50:18.449Z','2026-07-04 12:52:56','2026-07-04 12:52:56',3,10,'2026-07-04T12:50:18.449Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:12036','tvmaze','tvmaze:show:12036','completed',105,'Altered Carbon','Altered Carbon is set in the 25th century when the human mind has been digitized and the soul itself is transferable from one body to the next. Takeshi Kovacs, a former elite interstellar warrior known as an Envoy who has been imprisoned for 250 years, is downloaded into a future he''d tried to stop. If he can solve a single murder in a world where technology has made death nearly obsolete, he''ll get a chance at a new life on Earth.','https://static.tvmaze.com/uploads/images/medium_portrait/240/602152.jpg','2018-02-02',NULL,'2026-07-04T12:50:19.851Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,8,'2026-07-04T12:50:19.851Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:11538','tvmaze','tvmaze:show:11538','watching',106,'Barry','Barry is a dark comedy about a depressed, low-rent hitman from the Midwest. Lonely and dissatisfied in his life, he reluctantly travels to Los Angeles to execute a hit on an aspiring actor. Barry follows his "mark" into an acting class and ends up finding an accepting community in a group of eager hopefuls within the LA theater scene. He wants to start a new life as an actor, but his criminal past won''t let him walk away - can he find a way to balance both worlds?','https://static.tvmaze.com/uploads/images/medium_portrait/455/1138151.jpg','2018-03-25',NULL,'2026-07-04T12:50:21.177Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,7,'2026-07-04T12:50:21.177Z');
