INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:33320','tvmaze','tvmaze:show:33320','completed',114,'Derry Girls','16-year-old Erin Quinn lives with her uncompromising mother, her long-suffering father and the fearsome ‘Granda Joe'', a man whose love for his daughters and granddaughters is surpassed only by his contempt for his son-in-law.It''s the early 90s, and Erin is used to seeing her country on the nightly news and speaking in acronyms (The IRA, The UDA, The RUC). This is a time of armed police in armoured Land Rovers and British Army check points. But it''s also the time of Murder She Wrote, The Cranberries, MJ and Lisa Marie, Doc Martens, bomber jackets, The X Files, Nirvana and Wayne''s World. And while The Troubles may hang over her home town, Erin has troubles of her own','https://static.tvmaze.com/uploads/images/medium_portrait/402/1007479.jpg','2018-01-04',NULL,'2026-07-04T12:50:27.330Z','2026-07-04 12:52:56','2026-07-04 12:52:56',3,7,'2026-07-04T12:50:27.330Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:22371','tvmaze','tvmaze:show:22371','watching',116,'The Rain','Ten years after a brutal virus has wiped out most of the population in Scandinavia, two young siblings embark on a search for safety. Only guided by their father''s notebook about the virus and the hazards of this new world, they start a dangerous journey through the country joining a group of other young survivors. Facing grave perils, the group must quickly realize that the greatest danger does not come from the outside - it comes from within.','https://static.tvmaze.com/uploads/images/medium_portrait/202/505919.jpg','2018-05-04',NULL,'2026-07-04T12:50:28.655Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,6,'2026-07-04T12:50:28.655Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:28278','tvmaze','tvmaze:show:28278','completed',117,'Miracle Workers','Miracle Workers is a seasonal anthology series based on Simon Rich''s books.The first season is based on What in God''s Name, and turns the perception of heaven on its head while also making the case that humans are worth saving.The second season is based on Revolution, and centers upon a group of medieval villagers trying to stay positive in an age of extreme income inequality, poor healthcare, and widespread ignorance.','https://static.tvmaze.com/uploads/images/medium_portrait/445/1113843.jpg','2019-02-12',NULL,'2026-07-04T12:50:29.681Z','2026-07-04 12:52:56','2026-07-04 12:52:56',4,10,'2026-07-04T12:50:29.681Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:18197','tvmaze','tvmaze:show:18197','plan-to-watch',120,'Sacred Games','Set in Mumbai, Sacred Games delves into the city''s intricate web of organized crime, corruption, politics and espionage that lie beneath India''s economic renaissance. It is an epic masterwork of exceptional richness and power that interweaves the lives of the privileged, the famous, the wretched and the bloodthirsty.','https://static.tvmaze.com/uploads/images/medium_portrait/204/511629.jpg','2018-07-06',NULL,'2026-07-04T12:50:31.314Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,0,'2026-07-04T12:50:31.314Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:70061','tvmaze','tvmaze:show:70061','plan-to-watch',121,'The Haunting','Jiang Shuo, accidentally took over the business of buying and selling houses, where the gruesome murders took places. Together with his partner Qin Yi Heng, through his bravery and ingenuity, as well as his determination to break the stigma around the houses, he helps the homeowners to break the rumors and allow the buildings to return to the market for sale. But is it really true, that bad reputation of the locations, is based only on urban legend or those buildings really hides some dark secrets?','https://static.tvmaze.com/uploads/images/medium_portrait/469/1174938.jpg','2023-07-17',NULL,'2026-07-04T12:50:32.299Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,0,'2026-07-04T12:50:32.299Z');
