INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:31365','tvmaze','tvmaze:show:31365','watching',126,'Manifest','When Montego Air Flight 828 landed safely after a turbulent but routine flight, the crew and passengers were relieved. But in the span of those few hours, the world had aged five years - and their friends, families and colleagues, after mourning their loss, had given up hope and moved on. Now, faced with the impossible, they''re all given a second chance. But as their new realities become clear, a deeper mystery unfolds and some of the returned passengers soon realize they may be meant for something greater than they ever thought possible.','https://static.tvmaze.com/uploads/images/medium_portrait/462/1155059.jpg','2018-09-24',NULL,'2026-07-04T12:50:36.958Z','2026-07-04 12:52:56','2026-07-04 12:52:56',3,13,'2026-07-04T12:50:36.958Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:36708','tvmaze','tvmaze:show:36708','watching',127,'Legacies','Continuing the tradition of The Vampire Diaries and The Originals, the story of the next generation of supernatural beings at The Salvatore School for the Young and Gifted. Klaus Mikaelson''s daughter, 17-year-old Hope Mikaelson; Alaric Saltzman''s twins, Lizzie and Josie Saltzman; and other young adults come of age in the most unconventional way possible, nurtured to be their best selves…in spite of their worst impulses. Will these young witches, vampires and werewolves become the heroes they want to be — or the villains they were born to be?','https://static.tvmaze.com/uploads/images/medium_portrait/364/911065.jpg','2018-10-25',NULL,'2026-07-04T12:50:38.289Z','2026-07-04 12:52:56','2026-07-04 12:52:56',4,1,'2026-07-04T12:50:38.289Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:37675','tvmaze','tvmaze:show:37675','watching',128,'The Dragon Prince','An extraordinary discovery inspires two human princes and an elven assassin to team up on an epic quest to bring peace to their warring lands.','https://static.tvmaze.com/uploads/images/medium_portrait/214/536527.jpg','2018-09-14',NULL,'2026-07-04T12:50:39.416Z','2026-07-04 12:52:56','2026-07-04 12:52:56',3,9,'2026-07-04T12:50:39.416Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:31339','tvmaze','tvmaze:show:31339','completed',130,'A Discovery of Witches','Brilliant historian Diana Bishop is a witch denying her own heritage. But when she unexpectedly calls up an ancient, bewitched manuscript from Oxford''s Bodleian library, one that was thought by the creatures to be lost and could answer the mysteries of their existence, she finds herself thrown into the heart of a dangerous mystery – and into the path of the enigmatic geneticist and vampire Matthew Clairmont.Matthew is driven to solve the looming threat of the creatures'' decline and extinction, but their unlikely alliance to find the book before it falls into the wrong hands – and their deepening relationship – threatens to violate age-old taboos and shake the fragile peace that exists between the species.','https://static.tvmaze.com/uploads/images/medium_portrait/388/972242.jpg','2018-09-14',NULL,'2026-07-04T12:50:40.740Z','2026-07-04 12:52:56','2026-07-04 12:52:56',3,7,'2026-07-04T12:50:40.740Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:33836','tvmaze','tvmaze:show:33836','completed',131,'Wayne','Wayne can''t help himself from righting the world''s wrongs. Now, against all odds, he and his one-of-a-kind girlfriend Del are on a road trip from Brockton, Mass to Ocala, Florida to reclaim what''s rightfully his: a majestic old car that was stolen from his sick father. With trouble behind them and danger ahead, Wayne and Del are bound to find themselves with their backs against the wall. But that''s okay. They''ve been there before.','https://static.tvmaze.com/uploads/images/medium_portrait/278/695982.jpg','2019-01-16',NULL,'2026-07-04T12:50:41.768Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,10,'2026-07-04T12:50:41.768Z');
