INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:39121','tvmaze','tvmaze:show:39121','completed',133,'The Last Empress','Set in an alternate universe, in which Korea is a constitutional monarchy in 2018, Oh Sunny is a bright and vivacious musical actress who marries the emperor. She becomes involved in the palace power struggle and a mysterious murder that sets off events that threaten the monarchy itself, while searching for true love and happiness.','https://static.tvmaze.com/uploads/images/medium_portrait/563/1409100.jpg','2018-11-21',NULL,'2026-07-04T12:50:43.810Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,52,'2026-07-04T12:50:43.810Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:15299','tvmaze','tvmaze:show:15299','completed',136,'The Boys','In a world where superheroes embrace the darker side of their massive celebrity and fame, The Boys centres on a group of vigilantes known informally as "The Boys," who set out to take down corrupt superheroes with no more than blue collar grit and a willingness to fight dirty.','https://static.tvmaze.com/uploads/images/medium_portrait/619/1547768.jpg','2019-07-26',NULL,'2026-07-04T12:50:45.459Z','2026-07-04 12:52:56','2026-07-04 12:52:56',5,8,'2026-07-04T12:50:45.459Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:36745','tvmaze','tvmaze:show:36745','completed',137,'Doom Patrol','A re-imagining of one of DC''s most beloved group of outcast super heroes: Robotman, Negative Man, Elasti-Woman and Crazy Jane, led by modern-day mad scientist Dr. Niles Caulder (The Chief). The Doom Patrol''s members each suffered horrible accidents that gave them superhuman abilities - but also left them scarred and disfigured. Traumatized and downtrodden, the team found purpose through The Chief, who brought them together to investigate the weirdest phenomena in existence - and to protect Earth from what they find. Part support group, part Super Hero team, the Doom Patrol is a band of super-powered freaks who fight for a world that wants nothing to do with them. Picking up after the events of Titans, Doom Patrol finds these reluctant heroes in a place they never expected to be, called to action by none other than Cyborg, who comes to them with a mission hard to refuse, but with a warning that is hard to ignore: their lives will never, ever be the same.','https://static.tvmaze.com/uploads/images/medium_portrait/481/1204053.jpg','2019-02-15',NULL,'2026-07-04T12:50:46.477Z','2026-07-04 12:52:56','2026-07-04 12:52:56',4,12,'2026-07-04T12:50:46.477Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:35083','tvmaze','tvmaze:show:35083','watching',138,'The Wheel of Time','The Wheel of Time is set in a sprawling, epic world where magic exists, but only women can use it safely. Meaning that in this series — women hold the keys to power. The story follows Moiraine, a member of the shadowy and influential all-female organization called the ‘Aes Sedai'' as she embarks on a dangerous, world-spanning journey with five young men and women. Moiraine''s interested in these five because she believes one of them might be the reincarnation of an incredibly powerful individual, whom prophecies say will either save humanity or destroy it. The series draws on numerous elements of European and Asian culture and philosophy, most notably the cyclical nature of time found in Buddhism and Hinduism.','https://static.tvmaze.com/uploads/images/medium_portrait/564/1411765.jpg','2021-11-19',NULL,'2026-07-04T12:50:47.500Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,8,'2026-07-04T12:50:47.500Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:41414','tvmaze','tvmaze:show:41414','plan-to-watch',139,'For All Mankind','Imagine a world where the global space race never ended. This thrilling "what if" take on history from Ronald D. Moore (Outlander, Battlestar Galactica) spotlights the high-stakes lives of NASA astronauts and their families.','https://static.tvmaze.com/uploads/images/medium_portrait/616/1541416.jpg','2019-11-01',NULL,'2026-07-04T12:50:48.424Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,0,'2026-07-04T12:50:48.424Z');
