INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:37120','tvmaze','tvmaze:show:37120','watching',141,'Modern Love','An unlikely friendship. A lost love resurfaced. A marriage at its turning point. A date that might not have been a date. An unconventional new family. These are unique stories about the joys and tribulations of love, each inspired by a real-life personal essay from the beloved New York Times column "Modern Love."','https://static.tvmaze.com/uploads/images/medium_portrait/206/516330.jpg','2019-10-18',NULL,'2026-07-04T12:50:50.472Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,8,'2026-07-04T12:50:50.472Z');
