INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:28717','tvmaze','tvmaze:show:28717','completed',144,'Good Omens','According to The Nice and Accurate Prophecies of Agnes Nutter, Witch (the world''s only completely accurate book of prophecies), the world will end on a Saturday. Next Saturday, in fact. Just before dinner.So the armies of Good and Evil are amassing, Atlantis is rising, tempers are flaring. Everything appears to be going according to Divine Plan. Except Aziraphale, a somewhat fussy angel, and Crowley, a fast-living demon--both of whom have lived among Earth''s mortals since The Beginning and have grown rather fond of the lifestyle--are not actually looking forward to the coming war.And someone seems to have misplaced the Antichrist...','https://static.tvmaze.com/uploads/images/medium_portrait/625/1563341.jpg','2019-05-31',NULL,'2026-07-04T12:50:53.639Z','2026-07-04 12:52:56','2026-07-04 12:52:56',3,1,'2026-07-04T12:50:53.639Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:36666','tvmaze','tvmaze:show:36666','completed',145,'Looking for Alaska','Looking for Alaska thrusts us into the perspective of Miles "Pudge" Halter who is done with his safe life at home. His whole life has been one big non-event, and his obsession with famous last words has only made him crave "the Great Perhaps" even more (Francois Rabelais, poet). He heads off to the sometimes crazy and anything-but-boring world of Culver Creek Boarding School, and his life becomes the opposite of safe. Because down the hall is Alaska Young. The gorgeous, clever, funny, sexy, self-destructive, screwed up, and utterly fascinating Alaska Young. She is an event unto herself. She pulls Pudge into her world, launches him into the Great Perhaps, and steals his heart. Then. . . After. Nothing is ever the same.','https://static.tvmaze.com/uploads/images/medium_portrait/209/523206.jpg','2019-10-18',NULL,'2026-07-04T12:50:54.668Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,8,'2026-07-04T12:50:54.668Z');
