INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:30770','tvmaze','tvmaze:show:30770','completed',149,'Chernobyl','Chernobyl dramatizes the true story of one of the worst man-made catastrophes in history and tells of the brave men and women who sacrificed to save Europe from unimaginable disaster. The miniseries focuses on the heartbreaking scope of the nuclear plant disaster that occurred in Ukraine in April 1986, revealing how and why it happened and telling the shocking, remarkable stories of the heroes who fought and fell.','https://static.tvmaze.com/uploads/images/medium_portrait/193/482599.jpg','2019-05-06',NULL,'2026-07-04T12:50:58.045Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,5,'2026-07-04T12:50:58.045Z');
