INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:40357','tvmaze','tvmaze:show:40357','watching',165,'Evil','Evil is a psychological mystery that examines the origins of evil along the dividing line between science and religion. The series focuses on a skeptical female psychologist who joins a priest-in-training and a carpenter as they investigate the Church''s backlog of unexplained mysteries, including supposed miracles, demonic possessions, and hauntings. Their job is to assess if there is a logical explanation or if something truly supernatural is at work.','https://static.tvmaze.com/uploads/images/medium_portrait/528/1321353.jpg','2019-09-26',NULL,'2026-07-04T12:51:11.976Z','2026-07-04 12:52:56','2026-07-04 12:52:56',3,2,'2026-07-04T12:51:11.976Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:35017','tvmaze','tvmaze:show:35017','completed',166,'Devs','Devs focuses on a young software engineer named Lily Chan who works for Amaya, a cutting-edge tech company based in Silicon Valley. After her boyfriend''s apparent suicide, Lily suspects foul play and begins to investigate. She quickly realizes that all roads lead to Forest, Amaya''s enigmatic CEO, and Devs, the company''s secret development division. In Lily''s quest to discover the truth, she uncovers a technology-based conspiracy that could change the world.','https://static.tvmaze.com/uploads/images/medium_portrait/244/611263.jpg','2020-03-05',NULL,'2026-07-04T12:51:12.992Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,8,'2026-07-04T12:51:12.992Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:33487','tvmaze','tvmaze:show:33487','watching',167,'Gangs of London','Set in the heart of one of the world''s most dynamic and multicultural cities, Gangs of London tells the story of city being torn apart by the turbulent power struggles of the international gangs that control it and the sudden power vacuum that''s created when the head of London''s most powerful crime family is assassinated. For 20 years, Finn Wallace was the most powerful criminal in London. Billions of pounds flowed through his organisation each year. But now he''s dead—and nobody knows who ordered the hit. With rivals everywhere, it''s up to the impulsive Sean Wallace, with the help of the Dumani family headed by Ed Dumani to take his father''s place. if the situation wasn''t already dangerous enough, Sean''s assumption of power causes ripples in the world of international crime. Perhaps the one man who might be able to help him and be his ally is Elliot Finch, who up until now, has been one of life''s losers, a lowlife chancer with a mysterious interest in the Wallace family. But as the wind of fate blows, Elliot finds himself transported to the inner workings of the largest criminal organisation in London.','https://static.tvmaze.com/uploads/images/medium_portrait/558/1395281.jpg','2020-04-23',NULL,'2026-07-04T12:51:14.024Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,8,'2026-07-04T12:51:14.024Z');
