INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:43031','tvmaze','tvmaze:show:43031','watching',176,'Reacher','Reacher follows Jack Reacher, a veteran military police investigator who has just recently entered civilian life. Reacher is a drifter, carrying no phone and the barest of essentials as he travels the country and explores the nation he once served. When Reacher arrives in the small town of Margrave, Georgia, he finds a community grappling with its first homicide in 20 years. The cops immediately arrest him and eyewitnesses claim to place Reacher at the scene of the crime. While he works to prove his innocence, a deep-seated conspiracy begins to emerge, one that will require Reacher''s keen mind and hard-hitting fists to deal with. One thing above all is for sure: They picked the wrong guy to take the fall.','https://static.tvmaze.com/uploads/images/medium_portrait/557/1392929.jpg','2022-02-04',NULL,'2026-07-04T12:51:23.238Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,8,'2026-07-04T12:51:23.238Z');
