INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:52863','tvmaze','tvmaze:show:52863','plan-to-watch',235,'Beyond Evil','Beyond Evil will tell the story of two fearless men who are willing to go through extreme lengths in their pursuit of a returning serial killer. In the course of uncovering the murderer''s identity, the two are forced to look deeper than what the evidence seems to suggest and constantly question the innocence of all the people involved in the case, including themselves.','https://static.tvmaze.com/uploads/images/medium_portrait/294/735981.jpg','2021-02-19',NULL,'2026-07-04T12:52:16.077Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,0,'2026-07-04T12:52:16.077Z');
