INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:45856','tvmaze','tvmaze:show:45856','watching',237,'La Brea','When a massive sinkhole mysteriously opens in Los Angeles, it tears a family in half, separating mother and son from father and daughter. When part of the family find themselves in an unexplainable primeval world, alongside a disparate group of strangers, they must work to survive and uncover the mystery of where they are and if there is a way back home.','https://static.tvmaze.com/uploads/images/medium_portrait/500/1250675.jpg','2021-09-28',NULL,'2026-07-04T12:52:18.233Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,13,'2026-07-04T12:52:18.233Z');
