INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:56942','tvmaze','tvmaze:show:56942','watching',240,'Hellbound','In Hellbound, supernatural beings appear out of nowhere to condemn people to hell. It doesn''t matter whether these events are a blessing or a curse: a new religious group is interpreting them all as the will of the divine. What unfolds through this predicament is an intense and highly-charged story about people who must survive under conditions of utter social chaos.','https://static.tvmaze.com/uploads/images/medium_portrait/540/1351542.jpg','2021-11-19',NULL,'2026-07-04T12:52:21.293Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,6,'2026-07-04T12:52:21.293Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:54134','tvmaze','tvmaze:show:54134','plan-to-watch',241,'Dark Hole','A creature action thriller series about the desperate survival of the survivors among the mutant humans who drank a mysterious black smoke from the sinkhole and soon turned into monsters and quickly became a pandemonium.','https://static.tvmaze.com/uploads/images/medium_portrait/311/778591.jpg','2021-04-30',NULL,'2026-07-04T12:52:22.322Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,0,'2026-07-04T12:52:22.322Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:63451','tvmaze','tvmaze:show:63451','watching',242,'Chainsaw Man','Denji has a simple dream—to live a happy and peaceful life, spending time with a girl he likes. This is a far cry from reality, however, as Denji is forced by the yakuza into killing devils in order to pay off his crushing debts. Using his pet devil Pochita as a weapon, he is ready to do anything for a bit of cash. Unfortunately, he has outlived his usefulness and is murdered by a devil in contract with the yakuza. However, in an unexpected turn of events, Pochita merges with Denji''s dead body and grants him the powers of a chainsaw devil. Now able to transform parts of his body into chainsaws, a revived Denji uses his new abilities to quickly and brutally dispatch his enemies. Catching the eye of the official devil hunters who arrive at the scene, he is offered work at the Public Safety Bureau as one of them. Now with the means to face even the toughest of enemies, Denji will stop at nothing to achieve his simple teenage dreams.','https://static.tvmaze.com/uploads/images/medium_portrait/422/1056726.jpg','2022-10-11',NULL,'2026-07-04T12:52:23.461Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,12,'2026-07-04T12:52:23.461Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:54191','tvmaze','tvmaze:show:54191','plan-to-watch',243,'Katakomben','A group of Munich rich kids is celebrating an illegal rave in the catacombs under the main train station. There they meet the invisible: people who have been displaced by the system.','https://static.tvmaze.com/uploads/images/medium_portrait/300/750815.jpg','2021-03-11',NULL,'2026-07-04T12:52:24.476Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,0,'2026-07-04T12:52:24.476Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:36672','tvmaze','tvmaze:show:36672','watching',244,'Yellowjackets','Yellowjackets follows a girls'' high school soccer team. In 1975, the Dearborn High Yellowjackets became the first team in state history to qualify for the Girls'' U.S. Soccer Championship Series in Manchester, NH. They never got the chance to compete. Equal parts survival epic, horror story and pitch black coming of age, Yellowjackets tells the story of the (un)lucky survivors of a plane crash deep in the Ontario wilderness, chronicling their descent from a friendly, cooperative team to warring, cannibalistic clans. At the same time, it follows the lives they''ve attempted to piece back together nearly twenty-five years later, proving that the past is never really past and what began out in the wilderness is far from over.','https://static.tvmaze.com/uploads/images/medium_portrait/554/1387457.jpg','2021-11-14',NULL,'2026-07-04T12:52:25.501Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,9,'2026-07-04T12:52:25.501Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:47856','tvmaze','tvmaze:show:47856','plan-to-watch',245,'The Terminal List','Based on the best-selling novel by Jack Carr, The Terminal List follows James Reece after his entire platoon of Navy SEALs is ambushed during a high-stakes covert mission. Reece returns home to his family with conflicting memories of the event and questions about his culpability. However, as new evidence comes to light, Reece discovers dark forces working against him, endangering not only his life but the lives of those he loves.','https://static.tvmaze.com/uploads/images/medium_portrait/445/1114091.jpg','2022-07-01',NULL,'2026-07-04T12:52:26.526Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,0,'2026-07-04T12:52:26.526Z');
