INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:46573','tvmaze','tvmaze:show:46573','watching',247,'Ghosts','Samantha and Jay throw caution to the wind when they convert their recently inherited country estate into a bed-and-breakfast. Call it mislaid plans. Not only is the place falling apart, but it''s also inhabited by spirits of previous residents -- whom only Samantha can see and hear. Ghosts spins the funny, heartfelt story about a newfound dream that reveals connection and self-discovery aren''t just for the living.','https://static.tvmaze.com/uploads/images/medium_portrait/590/1475093.jpg','2021-10-07',NULL,'2026-07-04T12:52:28.824Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,17,'2026-07-04T12:52:28.824Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:54723','tvmaze','tvmaze:show:54723','watching',248,'FROM','FROM unravels the mystery of a nightmarish town that traps all those who enter. As the unwilling residents fight to keep a sense of normalcy and search for a way out, they must also survive the threats of the surrounding forest – including the terrifying creatures that come out when the sun goes down. In season two, hidden truths about the nature and terrifying origins of the town begin to emerge, even as life for its residents is plunged into chaos by the arrival of mysterious newcomers.','https://static.tvmaze.com/uploads/images/medium_portrait/621/1554646.jpg','2022-02-20',NULL,'2026-07-04T12:52:29.900Z','2026-07-04 12:52:56','2026-07-04 12:52:56',4,9,'2026-07-04T12:52:29.900Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:62248','tvmaze','tvmaze:show:62248','completed',249,'Alchemy of Souls','Set in a fictional country called Daeho that does not exist in history or on maps, it is about the love and growth of young mages as they overcome their twisted fates due to a magic spell known as the "alchemy of souls", which allows souls to switch bodies. It follows the story of an elite assassin named Naksu, whose soul is accidentally trapped inside the weak body of Moo Duk—Jang Wook''s servant from a powerful and noble family in the country. The young master of the Jang Family, Jang Wook, holds a dark secret about his scandalous birth. He wants the formidable assassin to help change his destiny.','https://static.tvmaze.com/uploads/images/medium_portrait/609/1523773.jpg','2022-06-18',NULL,'2026-07-04T12:52:30.924Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,10,'2026-07-04T12:52:30.924Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:53147','tvmaze','tvmaze:show:53147','plan-to-watch',250,'Black Bird','Inspired by actual events, when high school football hero, decorated policeman''s son and convicted drug dealer Jimmy Keene is sentenced to 10 years in a minimum security prison, he is given the choice of a lifetime — enter a maximum-security prison for the criminally insane and befriend suspected serial killer Larry Hall, or stay where he is and serve his full sentence with no possibility of parole. Keene quickly realizes his only way out is to elicit a confession and find out where the bodies of several young girls are buried before Hall''s appeal goes through. But is this suspected killer telling the truth? Or is it just another tale from a serial liar?','https://static.tvmaze.com/uploads/images/medium_portrait/501/1254750.jpg','2022-07-08',NULL,'2026-07-04T12:52:31.951Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,6,'2026-07-04T12:52:31.951Z');
