INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:46656','tvmaze','tvmaze:show:46656','watching',259,'Pantheon','Pantheon focuses on Maddie, a bullied teen who receives mysterious help from someone online. The stranger is soon revealed to be her recently deceased father, David, whose consciousness has been uploaded to the Cloud following an experimental destructive brain scan. David is the first of a new kind of being: an "Uploaded Intelligence" or "UI", but he will not be the last, as a global conspiracy unfolds that threatens to trigger a new kind of world war.Based short stories by Ken Liu','https://static.tvmaze.com/uploads/images/medium_portrait/436/1091844.jpg','2022-09-01',NULL,'2026-07-04T12:52:39.421Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,8,'2026-07-04T12:52:39.421Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:62998','tvmaze','tvmaze:show:62998','completed',260,'Gen V','From the world of The Boys comes Gen V, a thrilling new series set at America''s only college for superheroes. These gifted students put their moral boundaries to the test, competing for the university''s top ranking, and a chance to join The Seven, Vought International''s elite superhero team. When the school''s dark secrets come to light, they must decide what kind of heroes they want to become.','https://static.tvmaze.com/uploads/images/medium_portrait/587/1469203.jpg','2023-09-29',NULL,'2026-07-04T12:52:40.445Z','2026-07-04 12:52:56','2026-07-04 12:52:56',2,8,'2026-07-04T12:52:40.445Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:61235','tvmaze','tvmaze:show:61235','watching',261,'Bad Sisters','Set in the breath-taking coast of Ireland, Bad Sisters follows the lives of the Garvey sisters, who are bound together by the premature death of their parents and a promise to always protect one another. The tight-knit Garvey sisters have always looked out for each other. When their brother-in-law winds up dead, his life insurers launch an investigation to prove malicious intent - and set their sights on the sisters, all of whom had ample reason to kill him.','https://static.tvmaze.com/uploads/images/medium_portrait/540/1351090.jpg','2022-08-19',NULL,'2026-07-04T12:52:41.477Z','2026-07-04 12:52:56','2026-07-04 12:52:56',1,10,'2026-07-04T12:52:41.477Z');
