INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:111','tvmaze','tvmaze:show:111','plan-to-watch',39,'Once Upon a Time','Once Upon a Time is Fairy Tale Land. It''s filled with magic, monsters and all of the characters we all know from stories growing up. It''s real, and so are the people in it. But unlike the "happily ever after" you may have heard about, their stories continued, and The Evil Queen cast a Dark Curse over the land...This is Storybrooke. It''s a quiet, little New England town filled with people who go about their everyday lives with no idea who they really are. The Queen''s Curse has trapped them here and placed her in near-complete control. They have no real memories and no real hope.','https://static.tvmaze.com/uploads/images/medium_portrait/127/319360.jpg','2011-10-23',NULL,'2026-07-04T12:54:18.658Z','2026-07-04 12:55:35','2026-07-04 12:55:35',1,0,'2026-07-04T12:54:18.658Z');
