INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:175','tvmaze','tvmaze:show:175','plan-to-watch',50,'House of Cards','Based on the BBC miniseries of the same name, House of Cards follows Francis Underwood, the politician''s politician – masterful, beguiling, charismatic and ruthless. He and his equally ambitious wife Claire will stop at nothing to ensure their ascendancy. This wicked political drama slithers beneath the curtain and through the back halls of greed, sex, love and corruption in modern Washington D.C.','https://static.tvmaze.com/uploads/images/medium_portrait/169/424482.jpg','2013-02-01',NULL,'2026-07-04T12:54:22.927Z','2026-07-04 12:55:35','2026-07-04 12:55:35',1,0,'2026-07-04T12:54:22.927Z');
