INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:8873','tvmaze','tvmaze:show:8873','completed',85,'Timeless','Timeless tells the story of a mysterious criminal who steals a secret state-of-the-art time machine, intent on destroying America as we know it by changing the past. The only hope is an unexpected team: a scientist, a soldier and a history professor, who must use the machine''s prototype to travel back in time to critical events. While they must make every effort not to affect the past themselves, they must also stay one step ahead of this dangerous fugitive. But can this handpicked team uncover the mystery behind it all and end his destruction before it''s too late?','https://static.tvmaze.com/uploads/images/medium_portrait/146/367481.jpg','2016-10-03',NULL,'2026-07-04T12:54:26.945Z','2026-07-04 12:55:35','2026-07-04 12:55:35',2,12,'2026-07-04T12:54:26.945Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:15996','tvmaze','tvmaze:show:15996','completed',89,'Travelers','Hundreds of years from now, the last surviving humans discover the means of sending consciousness back through time, directly into people in the 21st century. These Travelers assume the lives of seemingly random people, while secretly working as teams to perform missions in order to save humanity from a terrible future.These travelers are: FBI Special Agent Grant MacLaren, the team''s leader; Marcy, a young, intellectually disabled woman in the care of her social worker, David; Trevor, a high school quarterback; Carly, a single mom in an abusive relationship; and Philip, a heroin-addicted college student.Armed only with their knowledge of history and an archive of social media profiles, the travelers discover that 21st century lives and relationships are as much a challenge as their high-stakes missions.','https://static.tvmaze.com/uploads/images/medium_portrait/176/441314.jpg','2016-10-17',NULL,'2026-07-04T12:54:28.995Z','2026-07-04 12:55:35','2026-07-04 12:55:35',3,10,'2026-07-04T12:54:28.995Z');
