INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:27557','tvmaze','tvmaze:show:27557','watching',115,'Titans','Titans follows young heroes from across the DC Universe as they come of age and find belonging in a gritty take on the classic Teen Titans franchise. Dick Grayson and Rachel Roth, a special young girl possessed by a strange darkness, get embroiled in a conspiracy that could bring Hell on Earth. Joining them along the way are the hot-headed Starfire and loveable Beast Boy. Together they become a surrogate family and team of heroes.','https://static.tvmaze.com/uploads/images/medium_portrait/457/1143752.jpg','2018-10-12',NULL,'2026-07-04T12:54:38.052Z','2026-07-04 12:55:35','2026-07-04 12:55:35',4,4,'2026-07-04T12:54:38.052Z');
