INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:14657','tvmaze','tvmaze:show:14657','completed',129,'Maniac','Set in a world somewhat like our world, in a time quite similar to our time, Maniac tells the stories of Annie Landsberg and Owen Milgrim, two strangers drawn to the late stages of a mysterious pharmaceutical trial, each for their own reasons. Annie''s disaffected and aimless, fixated on broken relationships with her mother and her sister; Owen, the fifth son of wealthy New York industrialists, has struggled his whole life with a disputed diagnosis of schizophrenia. Neither of their lives have turned out quite right, and the promise of a new, radical kind of pharmaceutical treatment—a sequence of pills its inventor, Dr. James K. Mantleray, claims can repair anything about the mind, be it mental illness or heartbreak—draws them and ten other strangers to the facilities of Neberdine Pharmaceutical and Biotech for a three-day drug trial that will, they''re assured, with no complications or side-effects whatsoever, solve all of their problems, permanently. Things do not go as planned.','https://static.tvmaze.com/uploads/images/medium_portrait/163/409066.jpg','2018-09-21',NULL,'2026-07-04T12:54:45.679Z','2026-07-04 12:55:35','2026-07-04 12:55:35',1,10,'2026-07-04T12:54:45.679Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:214','tvmaze','tvmaze:show:214','watching',134,'Kingdom','Kingdom is a raw family drama set against the world of Mixed Martial Arts (MMA) in Venice, California. Alvey Kulina owns Navy St. MMA with the help of his girlfriend Lisa Prince. He is willing to go through extraordinary means to make sure his fighters are taken care of, but all of this responsibility comes at a steep price. He has complicated relationships with both of his sons, Jay and Nate, who are both struggling with their own identities and places within Alvey''s life and gym.','https://static.tvmaze.com/uploads/images/medium_portrait/116/291395.jpg','2014-10-08',NULL,'2026-07-04T12:54:47.739Z','2026-07-04 12:55:35','2026-07-04 12:55:35',2,6,'2026-07-04T12:54:47.739Z');
