INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:1382','tvmaze','tvmaze:show:1382','watching',152,'Dracula','Golden Globe winner Jonathan Rhys Meyers ("The Tudors") stars in this provocative new drama as one of the world''s most iconic characters. It''s the late 19th century and the mysterious Dracula (Rhys Meyers) has arrived in London, posing as an American entrepreneur who wants to bring modern science to Victorian society. He''s especially interested in the new technology of electricity, which promises to brighten the night - useful for someone who avoids the sun. But he has another reason for his travels: He hopes to take revenge on those who cursed him with immortality centuries earlier. Everything seems to be going according to plan... until he becomes infatuated with a woman who appears to be a reincarnation of his dead wife.','https://static.tvmaze.com/uploads/images/medium_portrait/7/19413.jpg','2013-10-25',NULL,'2026-07-04T12:54:54.800Z','2026-07-04 12:55:35','2026-07-04 12:55:35',1,3,'2026-07-04T12:54:54.800Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:36568','tvmaze','tvmaze:show:36568','completed',156,'Swamp Thing','Swamp Thing centers on CDC researcher Abby Arcane. When she returns to her childhood home of Houma, Louisiana, in order to investigate a deadly swamp-borne virus, she develops a surprising bond with scientist Alec Holland — only to have him tragically taken from her. But as powerful forces descend on Houma, intent on exploiting the swamp''s mysterious properties for their own purposes, Abby will discover that the swamp holds mystical secrets, both horrifying and wondrous — and the potential love of her life may not be dead after all.','https://static.tvmaze.com/uploads/images/medium_portrait/200/500171.jpg','2019-05-31',NULL,'2026-07-04T12:54:56.752Z','2026-07-04 12:55:35','2026-07-04 12:55:35',1,10,'2026-07-04T12:54:56.752Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:35951','tvmaze','tvmaze:show:35951','watching',177,'Foundation','When revolutionary Dr. Hari Seldon predicts the impending fall of the Empire, he and a band of loyal followers venture to the far reaches of the galaxy to establish The Foundation in an attempt to rebuild and preserve the future of civilization. Enraged by Hari''s claims, the ruling Cleons – a long line of emperor clones – fear their grasp on the galaxy may be weakening as they''re forced to reckon with the potential reality of losing their legacy forever.','https://static.tvmaze.com/uploads/images/medium_portrait/573/1433544.jpg','2021-09-24',NULL,'2026-07-04T12:54:58.786Z','2026-07-04 12:55:35','2026-07-04 12:55:35',3,10,'2026-07-04T12:54:58.786Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:43102','tvmaze','tvmaze:show:43102','watching',179,'Hawkeye','Marvel Studios'' Hawkeye is an original new series set in post-blip New York City where former Avenger Clint Barton aka Hawkeye has a seemingly simple mission: get back to his family for Christmas. But when a threat from his past shows up, Hawkeye reluctantly teams up with Kate Bishop, a 22-year-old skilled archer and his biggest fan, to unravel a criminal conspiracy.','https://static.tvmaze.com/uploads/images/medium_portrait/383/959105.jpg','2021-11-24',NULL,'2026-07-04T12:55:00.843Z','2026-07-04 12:55:35','2026-07-04 12:55:35',1,5,'2026-07-04T12:55:00.843Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:1122','tvmaze','tvmaze:show:1122','watching',183,'Amazing Stories','As one experience ends, another adventure begins… in the extraordinary worlds of Amazing Stories! From acclaimed director-producer Steven Spielberg and Amblin Entertainment comes the Emmy Award-winning TV series. Join a roster of cinema''s most illustrious stars, including Kiefer Sutherland, Charlie Sheen, Tim Robbins, John Lithgow, Kevin Costner and more, as well as some of Hollywood''s greatest directorial talents. Relive all the mesmerizing magic, mystery and suspense in these unique episodes from some of filmmaking''s finest storytellers!','https://static.tvmaze.com/uploads/images/medium_portrait/6/17262.jpg','1985-09-29',NULL,'2026-07-04T12:55:02.885Z','2026-07-04 12:55:35','2026-07-04 12:55:35',1,5,'2026-07-04T12:55:02.885Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:37196','tvmaze','tvmaze:show:37196','watching',189,'Invincible','Based on the eponymous comic book, Invincible revolves around Mark Grayson, a normal teenager except for the fact that his father is the most powerful superhero on the planet. Shortly after his 17th birthday, Mark begins to develop powers of his own and enters into his father''s tutelage.','https://static.tvmaze.com/uploads/images/medium_portrait/618/1545777.jpg','2021-03-26',NULL,'2026-07-04T12:55:04.940Z','2026-07-04 12:55:35','2026-07-04 12:55:35',4,8,'2026-07-04T12:55:04.940Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:39013','tvmaze','tvmaze:show:39013','completed',197,'Raised by Wolves','After Earth is torn apart by religious differences and the human race teeters on the edge of extinction, an atheistic android architect sends two of his creations, Mother and Father, to start a peaceful, godless colony on the planet Kepler-22b. Raised by Wolves follows Mother and Father as they attempt to raise human children in this mysterious virgin land, a treacherous and difficult task that''s jeopardized by the arrival of the Mithraic, a deeply devout religious order of surviving humans. As the androids make contact with this zealous and dangerous people, they struggle to control the beliefs of their fiercely self-determining children.','https://static.tvmaze.com/uploads/images/medium_portrait/389/974042.jpg','2020-09-03',NULL,'2026-07-04T12:55:06.986Z','2026-07-04 12:55:35','2026-07-04 12:55:35',2,8,'2026-07-04T12:55:06.986Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:35691','tvmaze','tvmaze:show:35691','completed',200,'Cursed','Cursed is told through the eyes of Nimue, the Lady of the Lake character from the King Arthur legend. Nimue is a teenager with a mysterious gift, and the series shows how she came to be on the road to her destiny. After her mother dies, Nimue joins a young mercenary named Arthur, on his quest to find the magician Merlin and deliver an ancient sword. The future Lady of the Lake become a symbol of courage and rebellion against the terrifying Red Paladins, and their complicit King Uther.','https://static.tvmaze.com/uploads/images/medium_portrait/255/639422.jpg','2020-07-17',NULL,'2026-07-04T12:55:08.979Z','2026-07-04 12:55:35','2026-07-04 12:55:35',1,10,'2026-07-04T12:55:08.979Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:50036','tvmaze','tvmaze:show:50036','watching',207,'Alice in Borderland','With his two friends, a video-game-obsessed young man finds himself in a strange version of Tokyo where they must compete in dangerous games to survive.Every episode lists different main cast in the opening sequence (beside the two main which are there throughout the entire series).','https://static.tvmaze.com/uploads/images/medium_portrait/589/1473249.jpg','2020-12-10',NULL,'2026-07-04T12:55:11.079Z','2026-07-04 12:55:35','2026-07-04 12:55:35',2,8,'2026-07-04T12:55:11.079Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:45325','tvmaze','tvmaze:show:45325','completed',222,'Around the World in 80 Days','Following an outrageous bet, Phileas Fogg and his valet, Passepartout, take on the legendary journey of circumnavigating the globe in just 80 days, swiftly joined by aspiring journalist Abigail Fix, who seizes the chance to report on this extraordinary story.','https://static.tvmaze.com/uploads/images/medium_portrait/379/948816.jpg','2021-12-11',NULL,'2026-07-04T12:55:13.132Z','2026-07-04 12:55:35','2026-07-04 12:55:35',1,8,'2026-07-04T12:55:13.132Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:8244','tvmaze','tvmaze:show:8244','watching',223,'Monster','Kenzou Tenma, a Japanese brain surgeon in Germany, had it all: incredible skill at his work, a rich and beautiful fiancee, and a promising career at his hospital. However, after becoming disenchanted by hospital politics, he chose to save the life of a young boy who got shot in the head over the life of the mayor. As a result he lost the support of the hospital director, as well as his position in the hospital and his fiance. A short time later, the hospital director and the doctors that replaced him were murdered, and once again he was catapulted back onto the top. But as the chief suspect of the murders, Tenma did not get a easy life. As a matter of fact, it seems that the boy he saved was much more than he had appeared to be... Now to clear his name and to correct his past mistake, Tenma must get to the bottom of these and other murders, and investigate the truth of the Monster who is.','https://static.tvmaze.com/uploads/images/medium_portrait/29/74582.jpg','2004-04-06',NULL,'2026-07-04T12:55:15.380Z','2026-07-04 12:55:35','2026-07-04 12:55:35',1,10,'2026-07-04T12:55:15.380Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:49964','tvmaze','tvmaze:show:49964','watching',252,'Invasion','Earth is visited by an alien species that threatens humanity''s existence. Events unfold in real time through the eyes of five ordinary people across the globe as they struggle to make sense of the chaos unraveling around them.','https://static.tvmaze.com/uploads/images/medium_portrait/589/1473271.jpg','2021-10-22',NULL,'2026-07-04T12:55:18.965Z','2026-07-04 12:55:35','2026-07-04 12:55:35',1,10,'2026-07-04T12:55:18.965Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:57680','tvmaze','tvmaze:show:57680','plan-to-watch',253,'Kaleidoscope','Spanning 24 years, Kaleidoscope centers around the largest heist ever attempted, and the vengeance, scheming, loyalties, and betrayals that surround it. It''s loosely inspired by the real-life story where seventy billion dollars in bonds went missing in downtown Manhattan during Hurricane Sandy.A heist thriller with a unique concept - eight episodes that can be watched in any order, with each episode featuring a different color code to indicate its place in the timeline.','https://static.tvmaze.com/uploads/images/medium_portrait/438/1097241.jpg','2023-01-01',NULL,'2026-07-04T12:55:20.909Z','2026-07-04 12:55:35','2026-07-04 12:55:35',1,8,'2026-07-04T12:55:20.909Z');
INSERT INTO "journal_shows" ("id","provider","provider_show_id","status","sort_order","show_name_snapshot","summary_snapshot","image_snapshot","premiered_snapshot","next_episode_air_date","metadata_refreshed_at","created_at","updated_at","current_season","current_episode","progress_updated_at") VALUES('tvmaze:show:472','tvmaze','tvmaze:show:472','watching',8,'X-Men','With stories adapted directly from the original comic books, this show is a piece of Marvel history and a must-have for every X-Men fan. Discover the origins of your favorite characters and uncover the secrets of Magneto and more of the world''s most diabolical villains in X-Men.Due to budget issues and issues with animation production deadlines not been met most episodes from Season 3 onwards aired out of production order, leading to some storylines not making any sense and creating plot holes, however this was somewhat rectified later with the DVD and streaming releases.','https://static.tvmaze.com/uploads/images/medium_portrait/305/764844.jpg','1992-10-31',NULL,'2026-07-04T12:56:27.205Z','2026-07-04 12:56:41','2026-07-04 12:56:41',1,1,'2026-07-04T12:56:27.205Z');
